const { ipcRenderer } = require('electron');
const Database = require('better-sqlite3');
const _fs = require('fs');
const _path = require('path');

// Database init — data lives in userData/cadence.db (follows --user-data-dir for tests)
const _dbPath = ipcRenderer.sendSync('get-db-path');
const _dbDir = _path.dirname(_dbPath);
if (!_fs.existsSync(_dbDir)) _fs.mkdirSync(_dbDir, { recursive: true });
const _db = new Database(_dbPath);
_db.prepare('CREATE TABLE IF NOT EXISTS store (key TEXT PRIMARY KEY, value TEXT NOT NULL)').run();

function dbGet(key) {
  const row = _db.prepare('SELECT value FROM store WHERE key = ?').get(key);
  return row ? row.value : null;
}
function dbSet(key, value) {
  _db.prepare('INSERT OR REPLACE INTO store (key, value) VALUES (?, ?)').run(key, String(value));
}
function dbRemove(key) {
  _db.prepare('DELETE FROM store WHERE key = ?').run(key);
}

// On first launch, copy any existing localStorage data into SQLite so nothing is lost
if (!dbGet('_migrated')) {
  ['tt_e','tt_c','tt_p','tt_t','tt_learn','tt_anchor','tt_mgview',
   'tt_qorder','tt_qidx','tt_qday','tt_theme','tt_dismissed_gaps'].forEach(k => {
    const v = localStorage.getItem(k);
    if (v !== null) dbSet(k, v);
  });
  dbSet('_migrated', '1');
}


async function doBackup() {
  if (testingMode) return; // never back up sample data
  await ipcRenderer.invoke('backup-data', JSON.stringify(E));
}
setInterval(doBackup, 60 * 60 * 1000); // every hour while app is open

// Restore saved anchor side on load
(function() { const a = dbGet('tt_anchor'); if (a) ipcRenderer.send('snap-to-edge', a); })();

