// ── Manage tree view state ────────────────────────────────────────────────────
let manageView = dbGet('tt_mgview') || 'subcats';
let manageViewLabel = manageView; // tracks the actual button clicked for highlighting
let expandedCats = new Set();
let expandedSubcats = new Set();
function applyManageView(mode) {
  if (mode === 'all') { expandedCats = new Set(C); expandedSubcats = new Set(P.map(p=>p.name)); }
  else if (mode === 'subcats' || mode === 'default') { expandedCats = new Set(C); expandedSubcats = new Set(); }
  else { expandedCats = new Set(); expandedSubcats = new Set(); } // 'cats' or 'clear'
}
function markActiveCttBtn(mode) {
  document.querySelectorAll('.ctt-btn').forEach(b => b.classList.remove('active'));
  // 'clear' has no persistent active state — it's a one-shot action
  if (mode === 'clear') return;
  // 'default' and 'subcats' both resolve to the subcats state
  const target = (mode === 'default') ? 'subcats' : mode;
  // Mark the first button whose data-view matches AND whose text matches the action
  // Default button is data-view=subcats but onclick=default, so match by button text instead
  const btnMap = { all: 'All', cats: 'Cats', subcats: 'Sub cats', default: 'Default' };
  const label = btnMap[mode];
  document.querySelectorAll('.ctt-btn').forEach(b => {
    if (b.childNodes[0]?.textContent?.trim() === label) b.classList.add('active');
  });
}
window.setManageView = function(mode) {
  manageViewLabel = mode;
  manageView = (mode === 'clear' || mode === 'default') ? 'subcats' : mode;
  dbSet('tt_mgview', manageView);
  applyManageView(mode);
  rmng(); // rmng calls markActiveCttBtn(manageViewLabel)
};
window.toggleCat = function(cat) {
  if (expandedCats.has(cat)) expandedCats.delete(cat); else expandedCats.add(cat);
  rmng();
};
window.toggleSubcat = function(proj) {
  if (expandedSubcats.has(proj)) expandedSubcats.delete(proj); else expandedSubcats.add(proj);
  rmng();
};
// Tooltip auto-dismiss after 5s
function wireTreeTooltips() {
  document.querySelectorAll('.ctt-btn, .cat-add-btn').forEach(btn => {
    const tip = btn.querySelector('.ctt-tip');
    if (!tip) return;
    let timer;
    btn.addEventListener('mouseenter', () => { clearTimeout(timer); tip.style.display='block'; timer=setTimeout(()=>{tip.style.display='none';},5000); });
    btn.addEventListener('mouseleave', () => { clearTimeout(timer); tip.style.display='none'; });
  });
}
