function generateTestEntries() {
  const cats = C.filter(c=>c!=='Break').length ? C.filter(c=>c!=='Break') : ['Development','Meetings','Admin','Research','Design'];
  const projs = P.length ? P.map(p=>p.name) : ['Project Alpha','Project Beta','Internal','Client Work','Infrastructure'];
  const descsByCat = {
    default: ['Team standup','Sprint planning','Code review','Client call','Documentation',
      'Emails and admin','Design review','Bug fixing','Feature development','1:1 with manager',
      'QA testing','Strategy session','Retrospective','Demo prep','User research',
      'Data analysis','Report writing','Training session','Onboarding call','Sync call',
      'Architecture review','Release prep','Stakeholder update','Workshop','Pair programming',
      'Performance review prep','Incident response','Deployment','Tech debt cleanup','Interview']
  };
  const getDesc = cat => {
    const pool = descsByCat[cat] || descsByCat.default;
    return pool[Math.floor(Math.random()*pool.length)];
  };
  const entries = [];
  const now = new Date();
  let id = Date.now() - 10000000;

  for (let daysBack = 0; daysBack < 730; daysBack++) {
    const d = new Date(now); d.setDate(now.getDate() - daysBack);
    const dow = d.getDay(); // 0=Sun, 6=Sat
    const isWeekend = dow === 0 || dow === 6;

    if (isWeekend && Math.random() < 0.93) continue; // ~7% weekend days get entries
    if (!isWeekend && Math.random() < 0.08) continue; // ~8% weekdays are off

    const dateStr = calFmt(d);
    const numEntries = isWeekend
      ? 1 + Math.floor(Math.random() * 2)              // 1-2 on rare weekend
      : 3 + Math.floor(Math.random() * 5);             // 3-7 on a workday

    let hour = isWeekend ? 9 + Math.floor(Math.random()*3) : 7 + Math.floor(Math.random()*2);
    let min = [0,15,30,45][Math.floor(Math.random()*4)];

    for (let i = 0; i < numEntries; i++) {
      const startH = hour, startM = min;
      const durOptions = isWeekend ? [30,45,60,90] : [15,30,30,45,45,60,60,75,90,120];
      const dur = durOptions[Math.floor(Math.random()*durOptions.length)];
      const total = hour * 60 + min + dur;
      if (total > (isWeekend ? 17 : 19) * 60) break;
      const eh = Math.floor(total/60), em = total%60;
      const start = String(startH).padStart(2,'0')+':'+String(startM).padStart(2,'0');
      const end   = String(eh).padStart(2,'0')+':'+String(em).padStart(2,'0');
      const cat  = cats[Math.floor(Math.random()*cats.length)];
      const proj = Math.random() > 0.28 ? projs[Math.floor(Math.random()*projs.length)] : '';
      const desc = getDesc(cat);
      // Occasional break entry (~12% of slots on workdays)
      if (!isWeekend && Math.random() < 0.12) {
        entries.push({id:id++, desc:'Lunch / break', cat:'Break', proj:'', date:dateStr, start, end, dur, tags:[]});
      } else {
        entries.push({id:id++, desc, cat, proj, date:dateStr, start, end, dur, tags:[]});
      }
      const gap = [0,0,0,15,15,30][Math.floor(Math.random()*6)];
      hour = eh; min = em + gap;
      if (min >= 60) { hour++; min -= 60; }
    }
  }
  return entries.sort((a,b) => b.date.localeCompare(a.date) || b.start.localeCompare(a.start));
}

function getWeekNum(d) {
  const date = new Date(d); date.setHours(0,0,0,0);
  date.setDate(date.getDate() + 3 - (date.getDay() + 6) % 7);
  const w1 = new Date(date.getFullYear(), 0, 4);
  return 1 + Math.round(((date.getTime() - w1.getTime()) / 86400000 - 3 + (w1.getDay() + 6) % 7) / 7);
}

// Shuffled quote order — generated once, persisted forever
let QORDER = JSON.parse(dbGet('tt_qorder') || 'null');
if (!QORDER || QORDER.length !== QUOTES.length) {
  QORDER = QUOTES.map((_, i) => i);
  for (let i = QORDER.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [QORDER[i], QORDER[j]] = [QORDER[j], QORDER[i]];
  }
  dbSet('tt_qorder', JSON.stringify(QORDER));
}

function initQuote() {
  const saved = dbGet('tt_qidx');
  const savedDay = dbGet('tt_qday');
  const now = new Date();
  const curDay = now.getFullYear() * 10000 + (now.getMonth()+1) * 100 + now.getDate();
  if (saved !== null && parseInt(savedDay) === curDay) {
    quoteIdx = parseInt(saved);
  } else {
    quoteIdx = curDay % QORDER.length;
    dbSet('tt_qidx', quoteIdx);
    dbSet('tt_qday', curDay);
  }
  renderQuote();
}

function renderQuote() {
  const q = QUOTES[QORDER[quoteIdx]];
  document.getElementById('quote-text').textContent = '”' + q.text + '”';
  document.getElementById('quote-author').textContent = '— ' + q.author;
}

window.prevQuote = function() {
  quoteIdx = (quoteIdx - 1 + QORDER.length) % QORDER.length;
  dbSet('tt_qidx', quoteIdx);
  renderQuote();
};
window.nextQuote = function() {
  quoteIdx = (quoteIdx + 1) % QORDER.length;
  dbSet('tt_qidx', quoteIdx);
  renderQuote();
};

function startClock() {
  function tick() {
    const now = new Date();
    document.getElementById('clock-time').textContent = String(now.getHours()).padStart(2,'0') + ':' + String(now.getMinutes()).padStart(2,'0');
    document.getElementById('clock-date').textContent = now.toLocaleDateString('en-NZ', {weekday:'short', day:'numeric', month:'short'});
  }
  tick();
  setInterval(tick, 1000);
}

const _themeImgCache = {};
window.setTheme = function(t) {
  document.body.className = t;
  dbSet('tt_theme', t);
  document.querySelectorAll('.theme-btn').forEach(b => b.classList.toggle('active', b.classList.contains(t)));
  if (t === 'space') {
    document.body.style.backgroundImage = 'url("' + SPACE_IMG + '")';
  } else if (['aurora', 'castle', 'sakura', 'woodland'].includes(t)) {
    if (!_themeImgCache[t]) {
      try {
        const imgPath = _path.join(__dirname, '..', t + '.jpg');
        const b64 = _fs.readFileSync(imgPath).toString('base64');
        _themeImgCache[t] = 'url("data:image/jpeg;base64,' + b64 + '")';
      } catch(e) { _themeImgCache[t] = ''; }
    }
    document.body.style.backgroundImage = _themeImgCache[t];
  } else {
    document.body.style.backgroundImage = '';
  }
};

window.resizeApp = function(mode) {
  ipcRenderer.send('resize-app', mode);
  document.body.classList.toggle('app-wide', mode === 'max');
};

