// ── Duplicate / similarity helpers ────────────────────────────────────────────
function _lev(a, b) {
  const m = a.length, n = b.length;
  if (!m) return n; if (!n) return m;
  const dp = Array.from({length: m+1}, (_,i) => Array.from({length: n+1}, (_,j) => i===0?j:j===0?i:0));
  for (let i=1;i<=m;i++) for (let j=1;j<=n;j++)
    dp[i][j] = a[i-1]===b[j-1] ? dp[i-1][j-1] : 1+Math.min(dp[i-1][j],dp[i][j-1],dp[i-1][j-1]);
  return dp[m][n];
}
// Returns { exact:true, match } for case-insensitive exact, { exact:false, match } for similar, or null
function findSimilar(name, list) {
  const n = name.toLowerCase().trim();
  if (!n) return null;
  const exact = list.find(i => i.toLowerCase() === n);
  if (exact) return { exact: true, match: exact };
  const sim = list.find(i => { const il=i.toLowerCase(); return il.includes(n)||n.includes(il)||_lev(il,n)<=2; });
  if (sim) return { exact: false, match: sim };
  return null;
}

// ── Combobox engine ───────────────────────────────────────────────────────────
function setComboVal(id, val) {
  const el = document.getElementById(id);
  if (el) { el.value = val; el.dataset.confirmed = val; }
}

function initCombo(cfg) {
  const el = document.getElementById(cfg.id);
  if (!el) return;
  el.dataset.confirmed = el.value || '';
  let dropEl = null;

  function showDrop(filter) {
    hideDrop();
    const rect = el.getBoundingClientRect();
    dropEl = document.createElement('div');
    dropEl.className = 'combo-drop';
    dropEl.style.cssText = `left:${rect.left}px;top:${rect.bottom+2}px;width:${rect.width}px;`;
    buildDrop(filter);
    document.body.appendChild(dropEl);
    const pr = dropEl.getBoundingClientRect();
    if (pr.right > window.innerWidth - 4) dropEl.style.left = Math.max(4, window.innerWidth - pr.width - 4) + 'px';
    if (pr.bottom > window.innerHeight - 4) dropEl.style.top = Math.max(4, rect.top - pr.height - 4) + 'px';
  }

  function buildDrop(filter) {
    if (!dropEl) return;
    const f = (filter || '').toLowerCase().trim();
    const list = f ? cfg.getItems().filter(i => i.toLowerCase().includes(f)) : cfg.getItems();
    let h = `<div class="combo-add-opt">+ ${cfg.addLabel}</div>`;
    h += list.map(i => `<div class="combo-opt${i===el.dataset.confirmed?' combo-hi':''}" data-v="${i.replace(/&/g,'&amp;').replace(/"/g,'&quot;')}">${i}</div>`).join('');
    if (!list.length && f) h += `<div class="combo-empty">No matches — use + above to add</div>`;
    dropEl.innerHTML = h;
    dropEl.querySelector('.combo-add-opt').addEventListener('mousedown', e => { e.preventDefault(); showAddNew(); });
    dropEl.querySelectorAll('.combo-opt').forEach(opt => {
      opt.addEventListener('mousedown', e => { e.preventDefault(); pick(opt.dataset.v); });
    });
  }

  function showAddStep2(projectName) {
    if (!dropEl) return;
    dropEl.innerHTML = `<div class="combo-new-wrap">
      <div style="font-size:9px;color:var(--muted);padding:2px 4px 6px;">Category for "<b>${projectName}</b>"</div>
      <input class="combo-new-inp" placeholder="Category…" autocomplete="off" spellcheck="false">
      <div class="combo-new-hint">Select or type · Enter to confirm · Esc to cancel</div>
    </div>`;
    const ni = dropEl.querySelector('.combo-new-inp');
    const listEl = document.createElement('div');
    dropEl.appendChild(listEl);

    function renderCats(filter) {
      const f = (filter || '').toLowerCase().trim();
      const matches = f ? C.filter(c => c.toLowerCase().includes(f)) : C;
      listEl.innerHTML = matches.map(c => `<div class="combo-opt" data-v="${c.replace(/&/g,'&amp;').replace(/"/g,'&quot;')}">${c}</div>`).join('');
      listEl.querySelectorAll('.combo-opt').forEach(opt => {
        opt.addEventListener('mousedown', e => {
          e.preventDefault();
          cfg.addItem(projectName, opt.dataset.v);
          pick(projectName);
        });
      });
    }

    renderCats('');
    ni.focus();
    ni.addEventListener('input', () => renderCats(ni.value));
    ni.addEventListener('keydown', e => {
      if (e.key === 'Enter') {
        e.preventDefault();
        const cat = ni.value.trim();
        if (!cat) return;
        const exact = C.find(c => c.toLowerCase() === cat.toLowerCase()) || cat;
        cfg.addItem(projectName, exact);
        pick(projectName);
      }
      if (e.key === 'Escape') { hideDrop(); el.focus(); }
    });
  }

  function showAddNew() {
    if (!dropEl) return;
    dropEl.innerHTML = `<div class="combo-new-wrap">
      <input class="combo-new-inp" placeholder="New name…" autocomplete="off" spellcheck="false">
      <div class="combo-new-hint">Enter to add · Esc to cancel</div>
    </div>`;
    const ni = dropEl.querySelector('.combo-new-inp');
    ni.focus();
    ni.addEventListener('input', () => {
      const sim = findSimilar(ni.value.trim(), cfg.getItems());
      ni.style.borderColor = (sim && sim.exact) ? '#e44' : '';
    });
    ni.addEventListener('keydown', e => {
      if (e.key === 'Enter') {
        e.preventDefault();
        const name = ni.value.trim();
        if (!name) return;
        // Exact match — just pick the existing one, don't create a duplicate
        const exact = cfg.getItems().find(i => i.toLowerCase() === name.toLowerCase());
        if (exact) { pick(exact); return; }
        // Similar match — ask before creating
        const sim = findSimilar(name, cfg.getItems());
        if (sim) {
          const typeLabel = cfg.addLabel.replace(/^add new\s*/i, '');
          hideDrop();
          showModal(
            `Similar ${typeLabel} exists`,
            `<b>${sim.match}</b> already exists.<br>Still create <b>${name}</b>?`,
            { fn: () => {
              if (cfg.addStep2) {
                // Show category picker in a follow-up modal
                const opts = C.map(c=>`<option value="${c.replace(/"/g,'&quot;')}">${c}</option>`).join('');
                showModal(`Category for "${name}"`,
                  `<select id="dup-cat" ${_modalInput()}><option value="">— category —</option>${opts}</select>`,
                  { fn: () => {
                    const cat=(document.getElementById('dup-cat')?.value||'').trim();
                    if (!cat) return;
                    cfg.addItem(name, cat);
                    pick(name);
                  }},
                  { confirm: 'Add', cancel: 'Cancel' }
                );
                return;
              }
              cfg.addItem(name);
              pick(name);
            }},
            { confirm: `Yes, save "${name}"`, cancel: `No, don't save` }
          );
          return;
        }
        if (cfg.addStep2) { showAddStep2(name); return; }
        cfg.addItem(name);
        pick(name);
      }
      if (e.key === 'Escape') { hideDrop(); el.focus(); }
    });
  }

  function pick(val) {
    el.value = val; el.dataset.confirmed = val;
    hideDrop();
    el.dispatchEvent(new Event('change', {bubbles:true}));
  }

  function hideDrop() { if (dropEl) { dropEl.remove(); dropEl = null; } }

  el.addEventListener('focus', () => showDrop(el.value));
  el.addEventListener('input', () => dropEl ? buildDrop(el.value) : showDrop(el.value));
  el.addEventListener('blur', () => {
    setTimeout(() => {
      if (document.activeElement && document.activeElement.closest && document.activeElement.closest('.combo-drop')) return;
      const v = el.value.trim();
      const exact = cfg.getItems().find(i => i.toLowerCase() === v.toLowerCase());
      if (exact) { el.value = exact; el.dataset.confirmed = exact; }
      else { el.value = el.dataset.confirmed || ''; }
      hideDrop();
    }, 160);
  });
  el.addEventListener('keydown', e => { if (e.key === 'Escape') { el.value = el.dataset.confirmed || ''; hideDrop(); } });
  el.addEventListener('keydown', function(e) {
    if (e.key !== 'Enter') return;
    if (!dropEl) return;
    const first = dropEl.querySelector('.combo-opt');
    if (!first) return;
    e.preventDefault();
    e.stopImmediatePropagation();
    pick(first.dataset.v);
  }, true);
}

// Init all four combos
initCombo({ id:'cat-sel',    getItems:()=>C,              addItem:name=>{C.push(name);sv();render();},             addLabel:'Add new category' });
