function applySuggestPick(item) {
  if (!item || !item.dataset) return;
  const catProjOnly = item.dataset.pickKind === 'catproj';
  const cat = item.dataset.pickCat || '';
  const proj = item.dataset.pickProj || '';
  if (!catProjOnly) {
    const d = item.dataset.pickDesc != null ? item.dataset.pickDesc : '';
    document.getElementById('desc').value = d;
  }
  if (cat) {
    setComboVal('cat-sel', cat);
    if (window.filterProjects) window.filterProjects();
    if (proj) setTimeout(() => { setComboVal('project', proj); }, 30);
    else setComboVal('project', '');
  }
  hideSuggestions();
}

function bindSuggestFieldKeynav(fieldId) {
  const field = document.getElementById(fieldId);
  if (!field) return;
  field.addEventListener('keydown', function(e) {
    const box = document.getElementById('suggest-box');
    if (!box) return;
    const items = Array.from(box.querySelectorAll('.suggest-item'));
    if (!items.length) return;
    if (e.key === 'ArrowDown') {
      e.preventDefault(); e.stopPropagation(); e.stopImmediatePropagation();
      highlightSuggest(suggestIdx < 0 ? 0 : suggestIdx + 1);
      return;
    }
    if (e.key === 'ArrowUp') {
      e.preventDefault(); e.stopPropagation(); e.stopImmediatePropagation();
      highlightSuggest(suggestIdx <= 0 ? items.length - 1 : suggestIdx - 1);
      return;
    }
    if (e.key === 'Enter') {
      const idx = suggestIdx >= 0 ? suggestIdx : 0;
      e.preventDefault(); e.stopPropagation(); e.stopImmediatePropagation();
      applySuggestPick(items[idx]);
      return;
    }
    if (e.key === 'Escape') {
      e.preventDefault(); e.stopPropagation(); e.stopImmediatePropagation();
      hideSuggestions();
    }
  }, true);
}
bindSuggestFieldKeynav('desc');

// ── Enter-key field navigation ────────────────────────────────────────────────
(function initFieldNav() {
  // Ordered list of skippable fields between desc and start
  const skipable = ['project','cat-sel'];

  function advanceFrom(fromId) {
    if (fromId === 'start') { document.getElementById('end').focus(); return; }
    // From desc, cat-sel or project: find next empty in the sequence
    const seq = ['cat-sel','project','start','end'];
    const startIdx = fromId === 'desc' ? 0 : seq.indexOf(fromId) + 1;
    const next = seq.slice(startIdx).map(id => document.getElementById(id)).find(el => el && !el.value);
    if (next) next.focus(); else window.addEntry();
  }

  const notesEl = document.getElementById('notes');
  if (notesEl) {
    notesEl.addEventListener('keydown', function(e) {
      if (e.key !== 'Enter' || e.shiftKey) return;
      e.preventDefault();
      const desc = document.getElementById('desc');
      if (desc) desc.focus();
    });
  }

  // End field: Enter is handled only by endFieldKeydown (fill time / submit) — do not duplicate here or addEntry runs twice.
  ['desc','project','cat-sel','start'].forEach(id => {
    const el = document.getElementById(id);
    if (!el) return;
    el.addEventListener('keydown', function(e) {
      if (e.key === 'Enter') { e.preventDefault(); advanceFrom(id); }
    });
  });
})();

