window.filterProjects = function() {
  // project is now a combobox input — value preserved automatically
};

function clearLogOutlines() {
  ['desc','cat-sel','project','start','end'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.style.outline = '';
  });
}

function showToast(msg) {
  let t = document.getElementById('val-toast');
  if (!t) { t = document.createElement('div'); t.id='val-toast'; t.className='val-toast'; document.body.appendChild(t); }
  t.textContent = msg; t.style.display = 'block';
  clearTimeout(t._hide); t._hide = setTimeout(() => t.style.display='none', 3500);
}

function showSaveFlash() {
  const el = document.getElementById('save-flash');
  if (!el) return;
  el.style.display = 'block';
  clearTimeout(el._hide);
  el._hide = setTimeout(() => { el.style.display = 'none'; }, 2000);
}

function clearNotesField() {
  const el = document.getElementById('notes');
  if (el) { el.value = ''; document.getElementById('notes-counter').textContent = '0 / 500'; }
}

window.addEntry = function() {
  const notes=(document.getElementById('notes')?.value||'').trim(),
    desc=document.getElementById('desc').value.trim(),cat=document.getElementById('cat-sel').value,proj=document.getElementById('project').value,
    date=document.getElementById('date').value,start=document.getElementById('start').value,end=document.getElementById('end').value,
    t1=document.getElementById('tag1').value,t2=document.getElementById('tag2').value,st=document.getElementById('status');
  const missing=[];
  const reqFields = [
    {id:'desc', val:desc, label:'description'},
    {id:'cat-sel', val:cat, label:'category'},
    {id:'project', val:proj, label:'sub category'},
    {id:'start', val:start, label:'start time'},
    {id:'end', val:end, label:'end time'}
  ];
  if(!desc) missing.push('description');
  if(!cat) missing.push('category');
  if(!proj) missing.push('sub category');
  if(!start) missing.push('start time');
  if(!end) missing.push('end time');
  if(missing.length) {
    const invalidFields = reqFields.filter(f => !f.val);
    invalidFields.forEach(f => {
      const el = document.getElementById(f.id);
      if (el) el.style.outline = '2px solid #e44';
    });
    invalidFields.forEach(f => {
      const el = document.getElementById(f.id);
      if (el) el.addEventListener('input', () => { el.style.outline = ''; }, { once: true });
    });
    clearLogOutlines._t && clearTimeout(clearLogOutlines._t);
    clearLogOutlines._t = setTimeout(clearLogOutlines, 3000);
    showToast('Required: ' + missing.join(', ') + '.');
    return false;
  }
  const sm=mins(start),em=mins(end);
  if(sm<0||em<0){showToast('Use HH:MM format, e.g. 09:00');return false;}
  if(em-sm<=0){showToast('End time must be after start time.');return false;}
  const tags=[t1,t2].filter(Boolean);
  if(editingId!==null){
    const idx=E.findIndex(x=>x.id===editingId);
    if(idx!==-1) E[idx]={...E[idx],notes,desc,cat,proj,date,start,end,dur:em-sm,tags};
    editingId=null;
    document.getElementById('add-btn').textContent='Add entry';
    sv();
    document.getElementById('desc').value='';document.getElementById('end').value='';
    document.getElementById('start').value=end;setComboVal('tag1','');setComboVal('tag2','');
    setComboVal('cat-sel','');setComboVal('project','');
    clearNotesField();
    st.textContent='Saved!';setTimeout(()=>st.textContent='',2000);
    entriesFilterDate = date;
    activeChips.clear();
    render();
    // Return to entries tab exactly as left
    const tabs=document.querySelectorAll('.tab');
    const panels=document.querySelectorAll('.panel');
    tabs.forEach(t=>t.classList.remove('active'));
    panels.forEach(p=>p.classList.remove('active'));
    tabs[1].classList.add('active');
    document.getElementById('tab-entries').classList.add('active');
    document.querySelector('.content').scrollTop = editReturnScroll;
    return false;
  } else {
    E.unshift({id:Date.now()+Math.random(),notes,desc,cat,proj,date,start,end,dur:em-sm,tags});
  }
  sv();
  document.getElementById('desc').value='';document.getElementById('end').value='';
  document.getElementById('start').value=end;document.getElementById('tag1').value='';document.getElementById('tag2').value='';
  document.getElementById('cat-sel').value='';document.getElementById('project').value='';
  clearNotesField();
  st.textContent='';
  showSaveFlash();
  render();
  setTimeout(() => { const n = document.getElementById('notes'); if (n) n.focus(); }, 0);
  return true;
};

window.del = function(id) {
  const entry = E.find(e => e.id === id);
  const label = entry ? `"${entry.desc}"` : 'this entry';
  showModal(
    'Delete entry?',
    `${label} will be permanently deleted. This cannot be undone.`,
    { fn: () => { E = E.filter(e => e.id !== id); sv(); render(); } },
    { confirm: 'Yes, delete entry', cancel: 'Cancel' }
  );
};

window.fillGap = function(date, start, end) {
  // Switch to Log tab and pre-fill the gap's time range
  window.calPick(date);
  document.getElementById('start').value = start;
  document.getElementById('end').value = end;
  syncEndField();
  document.getElementById('desc').value = '';
  setComboVal('cat-sel', '');
  setComboVal('project', '');
  document.querySelectorAll('.tab').forEach(t => t.classList.remove('active'));
  document.querySelectorAll('.panel').forEach(p => p.classList.remove('active'));
  document.querySelectorAll('.tab')[0].classList.add('active');
  document.getElementById('tab-log').classList.add('active');
  document.getElementById('desc').focus();
};

window.dismissGap = function(date, gapStart, gapEnd) {
  dismissedGaps.add(gapKey(date, gapStart, gapEnd));
  saveDismissedGaps();
  render();
};

window.editEntry = function(id) {
  const e=E.find(x=>x.id===id); if(!e) return;
  editingId=id;
  editReturnScroll = document.querySelector('.content').scrollTop;
  const notesEl = document.getElementById('notes');
  if (notesEl) { notesEl.value = e.notes||''; document.getElementById('notes-counter').textContent=(e.notes||'').length+' / 500'; }
  document.getElementById('desc').value=e.desc;
  window.calPick(e.date);
  document.getElementById('start').value=e.start;
  document.getElementById('end').value=e.end;
  syncEndField();
  setComboVal('cat-sel', e.cat||'');
  setComboVal('project', e.proj||'');
  setComboVal('tag1', (e.tags&&e.tags[0])||'');
  setComboVal('tag2', (e.tags&&e.tags[1])||'');
  document.querySelectorAll('.tab').forEach(t=>t.classList.remove('active'));
  document.querySelectorAll('.panel').forEach(p=>p.classList.remove('active'));
  document.querySelectorAll('.tab')[0].classList.add('active');
  document.getElementById('tab-log').classList.add('active');
  document.getElementById('add-btn').textContent='Save changes';
  document.getElementById('status').textContent='Editing — update fields and save.';
  document.getElementById('desc').focus();
  resetEntriesFilterToToday();
  render();
};

// ── Smart learning auto-suggest ──────────────────────────────────────────────
const STOP = new Set();

function extractWords(text) {
  return (text.toLowerCase().match(/\b[a-z]{3,}\b/g) || []).filter(w => !STOP.has(w));
}

function learnFromEntry(desc, cat, proj, skipSave) {
  if (!desc || !cat) return;
  const key = cat + (proj ? '::' + proj : '');
  extractWords(desc).forEach(w => {
    if (!LEARN[w]) LEARN[w] = {};
    LEARN[w][key] = (LEARN[w][key] || 0) + 1;
  });
  if (!skipSave) dbSet('tt_learn', JSON.stringify(LEARN));
}

function rebuildLearnFromEntries() {
  LEARN = {};
  E.forEach(e => { if (e.cat) learnFromEntry(e.desc, e.cat, e.proj, true); });
  if (!testingMode) dbSet('tt_learn', JSON.stringify(LEARN));
}

(function seedLearn() {
  rebuildLearnFromEntries();
})();

let suggestIdx = -1;
const LOG_SUGGEST_MIN_CHARS = 2;

function hideSuggestions() {
  const b = document.getElementById('suggest-box');
  if (b) b.remove();
  suggestIdx = -1;
}

function highlightSuggest(idx) {
  const items = Array.from((document.getElementById('suggest-box') || {querySelectorAll:()=>[]}).querySelectorAll('.suggest-item'));
  if (!items.length) return;
  suggestIdx = (idx + items.length) % items.length;
  items.forEach((el, i) => el.classList.toggle('active', i === suggestIdx));
  items[suggestIdx].scrollIntoView({ block: 'nearest' });
}

/** Rank category / sub category pairs from current E + LEARN + names, given description text (trimmed, len ≥ 2). */
function rankCatProjFromDescription(val) {
  const words = extractWords(val);
  const scores = {};
  E.forEach(e => {
    if (!e.cat) return;
    const key = e.cat + (e.proj ? '::' + e.proj : '');
    scores[key] = (scores[key] || 0) + 1;
  });
  words.forEach(w => {
    if (LEARN[w]) Object.entries(LEARN[w]).forEach(([key, n]) => {
      scores[key] = (scores[key] || 0) + n * 8;
    });
  });
  const typed = val.toLowerCase();
  C.forEach(c => {
    const cl = c.toLowerCase();
    const boost = words.some(w => cl.includes(w)) || cl.split(/\W+/).some(cw => typed.includes(cw) && cw.length > 2) ? 4 : 0;
    if (!boost) return;
    const projs = P.filter(p => p.cat === c);
    if (projs.length) projs.forEach(p => { scores[c+'::'+p.name] = (scores[c+'::'+p.name]||0) + boost; });
    else scores[c] = (scores[c]||0) + boost;
  });
  P.forEach(p => {
    const pl = p.name.toLowerCase();
    const boost = words.some(w => pl.includes(w)) || pl.split(/\W+/).some(pw => typed.includes(pw) && pw.length > 2) ? 4 : 0;
    if (boost) scores[p.cat+'::'+p.name] = (scores[p.cat+'::'+p.name]||0) + boost;
  });
  if (!Object.keys(scores).length) {
    C.forEach(c => {
      const projs = P.filter(p => p.cat === c);
      if (projs.length) projs.forEach(p => { scores[c+'::'+p.name] = 0.1; });
      else scores[c] = 0.1;
    });
  }
  return Object.entries(scores).sort((a, b) => b[1] - a[1]);
}

// Description field: past descriptions + category/sub category hints (not Details). All from current E / lists.
window.descSuggest = function(val, sourceId) {
  hideSuggestions();
  val = (val || '').trim();
  if (val.length < LOG_SUGGEST_MIN_CHARS) return;
  const typed = val.toLowerCase();
  const anchor = document.getElementById(sourceId || 'desc');
  if (!anchor) return;
  const rect = anchor.getBoundingClientRect();

  const descMap = {};
  E.forEach(e => {
    const d = (e.desc || '').trim();
    if (!d || !e.cat) return;
    if (!descMap[d]) descMap[d] = {};
    const key = e.cat + '::' + (e.proj || '');
    descMap[d][key] = (descMap[d][key] || 0) + 1;
  });
  const rows = Object.entries(descMap).map(([d, catMap]) => {
    const top = Object.entries(catMap).sort((a, b) => b[1] - a[1])[0];
    const [cat, proj] = (top?.[0] || '::').split('::');
    const count = Object.values(catMap).reduce((s, n) => s + n, 0);
    return { desc: d, cat, proj, count };
  }).sort((a, b) => b.count - a.count);
  const descMatches = rows.filter(r => r.desc.toLowerCase().includes(typed)).slice(0, 7);

  const catSel = document.getElementById('cat-sel');
  const projSel = document.getElementById('project');
  let catProjRanked = [];
  if (catSel && projSel && (!catSel.value || !projSel.value)) {
    catProjRanked = rankCatProjFromDescription(val).slice(0, 6);
  }

  if (!descMatches.length && !catProjRanked.length) return;

  const box = document.createElement('div');
  box.id = 'suggest-box';
  box.className = 'suggest-box';
  box.style.left = rect.left + 'px';
  box.style.top = (rect.bottom + 2) + 'px';
  box.style.width = rect.width + 'px';

  descMatches.forEach(({ desc, cat, proj }) => {
    const item = document.createElement('div');
    item.className = 'suggest-item';
    item.dataset.pickDesc = desc;
    item.dataset.pickCat = cat || '';
    item.dataset.pickProj = proj || '';
    const sp1 = document.createElement('span');
    sp1.className = 'suggest-cat';
    sp1.textContent = desc;
    item.appendChild(sp1);
    if (cat) {
      const sp2 = document.createElement('span');
      sp2.className = 'suggest-proj';
      sp2.textContent = proj ? cat + ' › ' + proj : cat;
      item.appendChild(sp2);
    }
    item.onmousedown = ev => { ev.preventDefault(); applySuggestPick(item); };
    box.appendChild(item);
  });

  catProjRanked.forEach(([key]) => {
    const [cat, proj] = key.split('::');
    const item = document.createElement('div');
    item.className = 'suggest-item';
    item.dataset.pickKind = 'catproj';
    item.dataset.pickCat = cat;
    item.dataset.pickProj = proj || '';
    const sp1 = document.createElement('span');
    sp1.className = 'suggest-cat';
    sp1.textContent = cat;
    item.appendChild(sp1);
    if (proj) {
      const sp2 = document.createElement('span');
      sp2.className = 'suggest-proj';
      sp2.textContent = '› ' + proj;
      item.appendChild(sp2);
    }
    item.onmousedown = ev => { ev.preventDefault(); applySuggestPick(item); };
    box.appendChild(item);
  });

  document.body.appendChild(box);
  highlightSuggest(0);
};

