function _focusModalInput(id) { setTimeout(()=>{ const el=document.getElementById(id); if(!el)return; el.focus(); el.addEventListener('keydown',e=>{if(e.key==='Enter'){e.preventDefault();window.confirmModal();}}); },30); }

