window.sr = function(type,key){ren={type,key};render();};
window.cr = function(){ren={};render();};
window.dr = function(type,old) {
  const el=document.getElementById('ri-'+type+'-'+old),val=el?el.value.trim():'';
  if(!val||val===old){ren={};render();return;}
  if(type==='cat'&&val.toLowerCase()==='uncategorised'){showToast('"Uncategorised" is reserved — choose a different name.');ren={};render();return;}
  if(type==='cat'){
    C=C.map(c=>c===old?val:c);P=P.map(p=>({...p,cat:p.cat===old?val:p.cat}));E=E.map(e=>({...e,cat:e.cat===old?val:e.cat}));
    if(expandedCats.has(old)){expandedCats.delete(old);expandedCats.add(val);}
  } else if(type==='proj'){
    P=P.map(p=>p.name===old?{...p,name:val}:p);E=E.map(e=>({...e,proj:e.proj===old?val:e.proj}));
    if(expandedSubcats.has(old)){expandedSubcats.delete(old);expandedSubcats.add(val);}
  } else{T=T.map(t=>t===old?val:t);E=E.map(e=>({...e,tags:e.tags.map(t=>t===old?val:t)}));}
  sv();ren={};render();
};
let _modalConfirm = null;
function showModal(title, body, confirmAction, opts) {
  _modalConfirm = confirmAction ? confirmAction.fn : null;
  const cancelLbl = (opts && opts.cancel) || (confirmAction ? 'Cancel' : 'OK');
  const confirmLbl = (opts && opts.confirm) || 'Confirm';
  const btns = confirmAction
    ? `<button class="modal-btn-danger" onclick="window.confirmModal()">${confirmLbl}</button><button onclick="window.closeModal()">${cancelLbl}</button>`
    : `<button onclick="window.closeModal()">${cancelLbl}</button>`;
  document.getElementById('tt-modal-box').innerHTML = `<div class="modal-title">${title}</div><div class="modal-body">${body}</div><div class="modal-btns">${btns}</div>`;
  document.getElementById('tt-modal').style.display = 'flex';
}
window.closeModal = function() { document.getElementById('tt-modal').style.display = 'none'; _modalConfirm = null; };
window.confirmModal = function() { if (_modalConfirm) _modalConfirm(); window.closeModal(); };

window.delCat = function(c) {
  const affected = E.filter(e => e.cat === c);
  const projCount = P.filter(p => p.cat === c).length;
  if (affected.length) {
    showModal(
      `Cannot delete "${c}"`,
      `<b>${affected.length}</b> entr${affected.length===1?'y':'ies'} ${affected.length===1?'is':'are'} assigned to this category${projCount?' and <b>'+projCount+'</b> sub categor'+(projCount===1?'y is':'ies are')+' linked to it':''}.<br><br>Reallocate ${affected.length===1?'it':'them'} before deleting.`
    );
    return;
  }
  showModal(
    `Delete category "${c}"?`,
    `<b>${c}</b> will be permanently removed.${projCount?' Its <b>'+projCount+'</b> sub categor'+(projCount===1?'y':'ies')+' will become uncategorised — their entries are untouched.':' It has no sub categories.'} This cannot be undone.`,
    { fn: () => { C=C.filter(x=>x!==c); P=P.map(p=>p.cat===c?{...p,cat:''}:p); expandedCats.delete(c); sv(); render(); } },
    { cancel: 'No, keep it', confirm: 'Yes, delete category' }
  );
};

window.delProj = function(n) {
  const affected = E.filter(e => e.proj === n);
  const cats = [...new Set(affected.map(e => e.cat).filter(Boolean))];
  if (affected.length) {
    showModal(
      `Cannot delete "${n}"`,
      `<b>${affected.length}</b> entr${affected.length===1?'y':'ies'} ${affected.length===1?'is':'are'} assigned to this sub category${cats.length?', across <b>'+cats.length+'</b> categor'+(cats.length===1?'y':'ies'):''}.<br><br>Reallocate ${affected.length===1?'it':'them'} before deleting.`
    );
    return;
  }
  showModal(
    `Delete sub category "${n}"?`,
    `<b>${n}</b> will be permanently removed. It currently has no entries, so nothing else changes. This cannot be undone.`,
    { fn: () => { P=P.filter(p=>p.name!==n); sv(); render(); } },
    { cancel: 'No, keep it', confirm: 'Yes, delete sub category' }
  );
};
window.delTag = function(t) {
  const count = E.filter(e=>e.tags.includes(t)).length;
  showModal(`Delete tag "${t}"?`,
    `<b>${t}</b> will be permanently removed.${count>0?` It will be stripped from <b>${count}</b> entr${count===1?'y':'ies'}.`:' It is not used on any entries.'} This cannot be undone.`,
    { fn: () => { T=T.filter(x=>x!==t); E=E.map(e=>({...e,tags:e.tags.filter(x=>x!==t)})); sv(); render(); }},
    { cancel:'No, keep it', confirm:'Yes, delete tag' }
  );
};


