function rdds() {
  // cat-sel, project, tag1, tag2 are combobox inputs — validate values against current data
  const catEl=document.getElementById('cat-sel');
  if(catEl.value&&!C.includes(catEl.value)){catEl.value='';catEl.dataset.confirmed='';}
  const projEl=document.getElementById('project');
  if(projEl.value&&!P.some(p=>p.name===projEl.value)){projEl.value='';projEl.dataset.confirmed='';}
  ['tag1','tag2'].forEach(id=>{const el=document.getElementById(id);if(el.value&&!T.includes(el.value)){el.value='';el.dataset.confirmed='';}});
}

function rmng() {
  const uP={},uT={};
  E.forEach(e=>{if(e.proj)uP[e.proj]=(uP[e.proj]||0)+1;e.tags.forEach(t=>{uT[t]=(uT[t]||0)+1;});});

  // ── Unified category tree ────────────────────────────────────────────────
  const treeEl = document.getElementById('cat-tree');
  if (!treeEl) { buildTagList(uT); return; }

  // Build groups: known cats first, then orphan sub-cats under 'Uncategorised'
  const sortedC = [...C].sort((a,b)=>a.localeCompare(b));
  const bycat = {};
  sortedC.forEach(c => bycat[c] = []);
  P.forEach(p => { const c = p.cat||'Uncategorised'; if(!bycat[c]) bycat[c]=[]; bycat[c].push(p); });
  Object.keys(bycat).forEach(c => bycat[c].sort((a,b)=>a.name.localeCompare(b.name)));
  // Add Uncategorised bucket if it has orphan sub-cats
  if (bycat['Uncategorised']?.length && !sortedC.includes('Uncategorised')) {
    sortedC.push('Uncategorised');
  }

  // Mark active view button
  markActiveCttBtn(manageViewLabel);

  function buildEntries(projName) {
    const entries = E.filter(e => e.proj === projName);
    if (!entries.length) return `<div class="entry-badge-wrap"><span style="font-size:9px;color:var(--muted);">No entries yet — drag sub categories here to move them</span></div>`;
    // Deduplicate by trimmed description
    const counts = {};
    entries.forEach(e => { const k=(e.desc||'(no description)').trim(); counts[k]=(counts[k]||0)+1; });
    const badges = Object.entries(counts).map(([desc, n]) => {
      const dEsc = desc.replace(/"/g,'&quot;');
      return `<div class="entry-badge" draggable="true" data-desc="${dEsc}" data-from="${projName.replace(/"/g,'&quot;')}"><span class="ebg">⠿</span>${desc}${n>1?`<span class="ebc">×${n}</span>`:''}</div>`;
    }).join('');
    return `<div class="entry-badge-wrap">${badges}</div>`;
  }

  function buildSubcats(cat) {
    const subcats = bycat[cat] || [];
    if (!subcats.length) return `<div style="padding:4px 8px;font-size:9px;color:var(--muted);">No sub categories</div>`;
    return subcats.map(p => {
      const pEsc = p.name.replace(/'/g,"\\'"), pNameEsc = p.name.replace(/"/g,'&quot;');
      const count = uP[p.name]||0;
      const isOpen = expandedSubcats.has(p.name);
      const editMode = ren.type==='proj' && ren.key===p.name;
      const hdr = editMode
        ? `<div class="subcat-row-hdr" style="cursor:default;"><input class="ri" id="ri-proj-${pEsc}" value="${p.name}" onkeydown="if(event.key==='Enter')window.dr('proj','${pEsc}')" style="flex:1"><button class="btn-sm" onclick="window.dr('proj','${pEsc}')">&#10003;</button><button class="btn-ghost" onclick="window.cr()">&#10005;</button></div>`
        : `<div class="subcat-row-hdr" draggable="true" data-proj="${pNameEsc}">
            <span class="drag-grip" style="font-size:11px;opacity:0.3;user-select:none;letter-spacing:-1px;">⠿</span>
            <span class="subcat-row-name" onclick="window.toggleSubcat('${pEsc}')">${p.name}</span>
            <button class="mi-count-btn" onclick="window.toggleSubcat('${pEsc}')" title="Click to view entries">${count}</button>
            <button class="btn-ghost" style="font-size:9px;padding:1px 5px;" onclick="window.sr('proj','${pEsc}')">Rename</button>
            <button class="btn-danger" style="font-size:9px;padding:1px 5px;" onclick="window.delProj('${pEsc}')">Del</button>
          </div>`;
      const entries = isOpen ? `<div class="subcat-row-entries open">${buildEntries(p.name)}</div>` : `<div class="subcat-row-entries"></div>`;
      return `<div class="subcat-row" data-proj="${pNameEsc}">${hdr}${entries}</div>`;
    }).join('');
  }

  const allCats = sortedC.filter(c => bycat[c]);
  treeEl.innerHTML = allCats.length ? allCats.map(cat => {
    const catEsc = cat.replace(/'/g,"\\'"), catNameEsc = cat.replace(/"/g,'&quot;');
    const isOpen = expandedCats.has(cat);
    const totalEntries = (bycat[cat]||[]).reduce((s,p)=>s+(uP[p.name]||0),0);
    const subcatCount = (bycat[cat]||[]).length;
    const editMode = ren.type==='cat' && ren.key===cat;
    const hdrContent = editMode
      ? `<input class="ri" id="ri-cat-${catEsc}" value="${cat}" onkeydown="if(event.key==='Enter')window.dr('cat','${catEsc}')" style="flex:1;"><button class="btn-sm" onclick="window.dr('cat','${catEsc}')">&#10003;</button><button class="btn-ghost" onclick="window.cr()">&#10005;</button>`
      : `<span class="cat-node-chev">&#9658;</span>
         <span class="cat-node-name" onclick="window.toggleCat('${catEsc}')">${cat}</span>
         <span class="cat-node-total" title="${subcatCount} sub cat${subcatCount===1?'':'s'}">${totalEntries} entries</span>
         <button class="cat-add-btn" onclick="event.stopPropagation();window.addSubcatToCat('${catEsc}')">＋<span class="ctt-tip">Click here to add a sub category to ${cat}</span></button>
         <button class="btn-ghost" style="font-size:9px;padding:1px 5px;" onclick="event.stopPropagation();window.sr('cat','${catEsc}')">Rename</button>
         <button class="btn-danger" style="font-size:9px;padding:1px 5px;" onclick="event.stopPropagation();window.delCat('${catEsc}')">Del</button>`;
    const body = isOpen ? `<div class="cat-node-body">${buildSubcats(cat)}</div>` : '';
    return `<div class="cat-node${isOpen?' open':''}" draggable="true" data-cat="${catNameEsc}">
      <div class="cat-node-hdr">${hdrContent}</div>${body}
    </div>`;
  }).join('') : `<div class="empty">No categories yet — add one above</div>`;

  // Wire subcat drag: merge & move-to-cat
  let dragProjName = null;
  const clearSubDrag = () => {
    treeEl.querySelectorAll('.subcat-row-hdr').forEach(el=>el.classList.remove('merge-target'));
    treeEl.querySelectorAll('.cat-node').forEach(el=>el.classList.remove('drag-over-cat'));
  };
  treeEl.querySelectorAll('.subcat-row-hdr[draggable]').forEach(el => {
    el.addEventListener('dragstart', e => {
      dragProjName = el.dataset.proj;
      setTimeout(()=>el.classList.add('dragging'),0);
      e.dataTransfer.effectAllowed='move';
      e.stopPropagation();
    });
    el.addEventListener('dragend', () => { el.classList.remove('dragging'); clearSubDrag(); });
    el.addEventListener('dragover', e => {
      const tgt = el.dataset.proj;
      if (!dragProjName || tgt===dragProjName) return;
      e.preventDefault(); e.stopPropagation(); clearSubDrag(); el.classList.add('merge-target');
    });
    el.addEventListener('dragleave', e => { if(!el.contains(e.relatedTarget)) el.classList.remove('merge-target'); });
    el.addEventListener('drop', e => {
      e.preventDefault(); e.stopPropagation(); clearSubDrag();
      const tgt = el.dataset.proj;
      if (!dragProjName || dragProjName===tgt) { dragProjName=null; return; }
      const src=dragProjName; dragProjName=null;
      const srcCount=E.filter(e=>e.proj===src).length;
      const tgtP = P.find(p=>p.name===tgt);
      const srcP2 = P.find(p=>p.name===src);
      const catNote2 = (srcP2?.cat && tgtP?.cat && srcP2.cat!==tgtP.cat) ? ` Their category will also change from <b>${srcP2.cat}</b> to <b>${tgtP.cat}</b>.` : '';
      showModal(`Merge "${src}" into "${tgt}"?`,
        `All <b>${srcCount}</b> entr${srcCount===1?'y':'ies'} currently filed under <b>${src}</b> will be moved to <b>${tgt}</b>.${catNote2} <b>${src}</b> will then be permanently removed. This cannot be undone.`,
        { fn: () => {
          E.forEach(e=>{ if(e.proj===src){ e.proj=tgt; const tp=P.find(p=>p.name===tgt); if(tp)e.cat=tp.cat; }});
          P.splice(P.findIndex(p=>p.name===src),1); sv(); render();
        }},
        { cancel:"Cancel — keep them separate", confirm:`Yes, merge "${src}" into "${tgt}"` }
      );
    });
  });

  // Wire cat drag: merge two categories
  let dragCatName = null;
  treeEl.querySelectorAll('.cat-node[draggable]').forEach(el => {
    el.addEventListener('dragstart', e => {
      if (e.target.closest('.subcat-row-hdr')) return; // let subcat handle it
      dragCatName = el.dataset.cat; dragProjName = null;
      setTimeout(()=>el.style.opacity='0.4',0);
      e.dataTransfer.effectAllowed='move';
    });
    el.addEventListener('dragend', () => { el.style.opacity=''; clearSubDrag(); dragCatName=null; });
    el.addEventListener('dragover', e => {
      if (!dragCatName || el.dataset.cat===dragCatName || dragProjName) return;
      e.preventDefault(); clearSubDrag(); el.classList.add('drag-over-cat');
    });
    el.addEventListener('dragleave', e => { if(!el.contains(e.relatedTarget)) el.classList.remove('drag-over-cat'); });
    el.addEventListener('drop', e => {
      el.classList.remove('drag-over-cat');
      const tgtCat = el.dataset.cat;
      if (!dragCatName || dragCatName===tgtCat || dragProjName) { dragCatName=null; return; }
      const srcCat=dragCatName; dragCatName=null;
      e.preventDefault();
      const srcSubcats = P.filter(p=>p.cat===srcCat);
      const srcEntries = E.filter(e=>e.cat===srcCat).length;
      // Check name collisions
      const tgtSubcatNames = new Set(P.filter(p=>p.cat===tgtCat).map(p=>p.name));
      const collisions = srcSubcats.filter(p=>tgtSubcatNames.has(p.name)).map(p=>p.name);
      const collisionNote = collisions.length ? `<br><b>Warning:</b> sub categories with the same name exist in both: <em>${collisions.join(', ')}</em> — these will both remain (you can merge them manually after).` : '';
      showModal(`Merge category "${srcCat}" into "${tgtCat}"?`,
        `Everything inside <b>${srcCat}</b> will move into <b>${tgtCat}</b>: <b>${srcSubcats.length}</b> sub categor${srcSubcats.length===1?'y':'ies'} and <b>${srcEntries}</b> entr${srcEntries===1?'y':'ies'}. <b>${srcCat}</b> will then be permanently removed.${collisionNote} This cannot be undone.`,
        { fn: () => {
          P.forEach(p=>{ if(p.cat===srcCat) p.cat=tgtCat; });
          E.forEach(e=>{ if(e.cat===srcCat) e.cat=tgtCat; });
          C.splice(C.indexOf(srcCat),1);
          expandedCats.delete(srcCat);
          sv(); render();
        }},
        { cancel:'Cancel', confirm:`Yes, merge "${srcCat}" into "${tgtCat}"` }
      );
    });
  });

  // Wire subcat drop onto cat body (move to different category)
  treeEl.querySelectorAll('.cat-node').forEach(catEl => {
    catEl.addEventListener('dragover', e => {
      if (!dragProjName || e.target.closest('.subcat-row-hdr')) return;
      e.preventDefault(); clearSubDrag(); catEl.classList.add('drag-over-cat');
    });
    catEl.addEventListener('dragleave', e => { if(!catEl.contains(e.relatedTarget)) catEl.classList.remove('drag-over-cat'); });
    catEl.addEventListener('drop', e => {
      catEl.classList.remove('drag-over-cat');
      if (!dragProjName || e.target.closest('.subcat-row-hdr')) return;
      const tgtCat = catEl.dataset.cat;
      const proj = P.find(p=>p.name===dragProjName);
      if (!proj || proj.cat===tgtCat) { dragProjName=null; return; }
      e.preventDefault();
      const src=dragProjName; dragProjName=null;
      const count=E.filter(e=>e.proj===src).length;
      const fromCatName = proj.cat||'Uncategorised';
      showModal(`Move "${src}" to "${tgtCat}"?`,
        `<b>${src}</b> will move from category <b>${fromCatName}</b> to <b>${tgtCat}</b>.${count>0?` All <b>${count}</b> entr${count===1?'y':'ies'} filed under it will reflect the new category.`:' It has no entries yet.'} This cannot be undone.`,
        { fn: () => { proj.cat=tgtCat; E.forEach(e=>{if(e.proj===src)e.cat=tgtCat;}); sv(); render(); }},
        { cancel:'Cancel', confirm:'Yes, move it' }
      );
    });
  });

  // Wire entry badge drag → drop onto subcat header
  let dragEntryDesc = null, dragEntryFromProj = null;
  const clearEntryDrop = () => treeEl.querySelectorAll('.entry-drop-target').forEach(el=>el.classList.remove('entry-drop-target'));
  const clearBadgeDrop = () => treeEl.querySelectorAll('.badge-drop-target').forEach(el=>el.classList.remove('badge-drop-target'));
  treeEl.querySelectorAll('.entry-badge[draggable]').forEach(badge => {
    badge.addEventListener('dragstart', e => {
      dragEntryDesc = badge.dataset.desc;
      dragEntryFromProj = badge.dataset.from;
      dragProjName = null; dragCatName = null;
      setTimeout(()=>badge.classList.add('dragging'),0);
      e.dataTransfer.effectAllowed = 'move';
      e.stopPropagation();
    });
    badge.addEventListener('dragend', () => { badge.classList.remove('dragging'); clearEntryDrop(); clearBadgeDrop(); dragEntryDesc=null; dragEntryFromProj=null; });
    // Click (not drag) = inline edit description
    badge.addEventListener('click', ev => {
      if (badge.classList.contains('editing')) return;
      const origDesc = badge.dataset.desc;
      const fromProj = badge.dataset.from;
      badge.classList.add('editing');
      badge.draggable = false;
      badge.innerHTML = `<input type="text" value="${origDesc.replace(/"/g,'&quot;')}" style="width:${Math.max(60,origDesc.length*6)}px;">`;
      const inp = badge.querySelector('input');
      inp.focus(); inp.select();
      let done = false;
      const save = () => {
        if (done) return; done = true; // set done BEFORE modal so blur doesn't also fire cancel
        const newDesc = inp.value.trim();
        if (!newDesc || newDesc === origDesc) { render(); return; }
        const matches = E.filter(e => e.proj===fromProj && (e.desc||'(no description)').trim()===origDesc);
        const n = matches.length;
        showModal(
          'Rename description?',
          `Changing <b>"${origDesc}"</b> to <b>"${newDesc}"</b> will update <b>${n} entr${n===1?'y':'ies'}</b> in <b>${fromProj}</b>. This cannot be undone.`,
          { fn: () => { matches.forEach(e => { e.desc = newDesc; }); sv(); render(); } },
          { confirm: `Yes, update ${n} entr${n===1?'y':'ies'}`, cancel: 'No, leave as is' }
        );
      };
      const cancel = () => { if (done) return; done = true; render(); };
      inp.addEventListener('keydown', e => {
        if (e.key==='Enter') { e.preventDefault(); save(); }
        if (e.key==='Escape') { e.preventDefault(); cancel(); }
      });
      inp.addEventListener('blur', () => setTimeout(cancel, 80));
    });
    // Drop onto another badge = merge descriptions
    badge.addEventListener('dragover', e => {
      if (!dragEntryDesc || badge.dataset.desc === dragEntryDesc) return;
      e.preventDefault(); e.stopPropagation(); clearEntryDrop(); clearBadgeDrop(); badge.classList.add('badge-drop-target');
    });
    badge.addEventListener('dragleave', e => { if(!badge.contains(e.relatedTarget)) badge.classList.remove('badge-drop-target'); });
    badge.addEventListener('drop', e => {
      if (!dragEntryDesc || badge.dataset.desc === dragEntryDesc) return;
      e.preventDefault(); e.stopPropagation(); clearBadgeDrop();
      const srcDesc=dragEntryDesc, srcProj=dragEntryFromProj;
      const tgtDesc=badge.dataset.desc, tgtProj=badge.dataset.from;
      dragEntryDesc=null; dragEntryFromProj=null;
      const srcMatches = E.filter(e=>e.proj===srcProj && (e.desc||'(no description)').trim()===srcDesc);
      if (!srcMatches.length) return;
      const crossSubcat = srcProj !== tgtProj;
      const tProj = crossSubcat ? P.find(p=>p.name===tgtProj) : null;
      const fromCat = srcMatches[0].cat||'Uncategorised';
      const toCat = tProj?.cat||fromCat;
      const moveNote = crossSubcat ? ` They will also move from sub category <b>${srcProj}</b> to <b>${tgtProj}</b>${toCat!==fromCat?` (category: <b>${fromCat}</b> → <b>${toCat}</b>)`:''}. ` : ' ';
      showModal(
        `Merge descriptions?`,
        `All <b>${srcMatches.length}</b> entr${srcMatches.length===1?'y':'ies'} currently described as <b>"${srcDesc}"</b> will be renamed to <b>"${tgtDesc}"</b>.${moveNote}This cannot be undone.`,
        { fn: () => {
          srcMatches.forEach(e => {
            e.desc = tgtDesc;
            if (crossSubcat) { e.proj=tgtProj; if(tProj) e.cat=tProj.cat; }
          });
          if (crossSubcat) { if(tProj?.cat) expandedCats.add(tProj.cat); expandedSubcats.add(tgtProj); }
          sv(); render();
        }},
        { cancel:'Cancel, keep them separate', confirm:'Yes, merge descriptions' }
      );
    });
  });
  treeEl.querySelectorAll('.subcat-row-hdr[draggable]').forEach(el => {
    el.addEventListener('dragover', e => {
      if (!dragEntryDesc || el.dataset.proj === dragEntryFromProj) return;
      e.preventDefault(); e.stopPropagation(); clearSubDrag(); clearEntryDrop(); el.classList.add('entry-drop-target');
    });
    el.addEventListener('dragleave', e => { if(!el.contains(e.relatedTarget)) el.classList.remove('entry-drop-target'); });
    el.addEventListener('drop', e => {
      if (!dragEntryDesc) return;
      e.preventDefault(); e.stopPropagation(); clearEntryDrop();
      const tgtProj = el.dataset.proj;
      if (tgtProj === dragEntryFromProj) { dragEntryDesc=null; return; }
      const desc=dragEntryDesc, fromProj=dragEntryFromProj;
      dragEntryDesc=null; dragEntryFromProj=null;
      const matches = E.filter(e=>e.proj===fromProj && (e.desc||'(no description)').trim()===desc);
      if (!matches.length) return;
      const tProj = P.find(p=>p.name===tgtProj);
      const fromCat = matches[0].cat||'Uncategorised';
      const toCat = tProj?.cat||'Uncategorised';
      const catNote = toCat!==fromCat ? ` and category <b>${toCat}</b>` : '';
      const label = matches.length>1 ? `<b>${matches.length}</b> entries named "<b>${desc}</b>"` : `"<b>${desc}</b>"`;
      showModal(`Move entries to "${tgtProj}"?`,
        `${label} will move from <b>${fromProj}</b> to sub category <b>${tgtProj}</b>${catNote}. Their descriptions stay the same. This cannot be undone.`,
        { fn: () => {
          matches.forEach(e=>{ e.proj=tgtProj; if(tProj) e.cat=tProj.cat; });
          if(tProj?.cat) expandedCats.add(tProj.cat);
          expandedSubcats.add(tgtProj);
          sv(); render();
        }},
        { cancel:'Cancel', confirm:'Yes, move them' }
      );
    });
  });

  wireTreeTooltips();
  buildTagList(uT);
}

function buildTagList(uT) {
  document.getElementById('tag-list').innerHTML = T.length
    ? T.map(t => {
        const esc=t.replace(/'/g,"\\'");
        if (ren.type==='tag'&&ren.key===t) return `<div class="mi"><input class="ri" id="ri-tag-${esc}" value="${t}" onkeydown="if(event.key==='Enter')window.dr('tag','${esc}')"><button class="btn-sm" onclick="window.dr('tag','${esc}')">&#10003;</button><button class="btn-ghost" onclick="window.cr()">&#10005;</button></div>`;
        return `<div class="mi"><span class="mi-name">${t}</span><span class="mi-count">${uT[t]||0}</span><button class="btn-ghost" onclick="window.sr('tag','${esc}')">Rename</button><button class="btn-danger" onclick="window.delTag('${esc}')">Del</button></div>`;
      }).join('')
    : '<div class="empty">None</div>';
}

// Inline entry move handlers

// ── Reports ───────────────────────────────────────────────────────────────────
let rptMode = 'day';
let rptAnchor = calFmt(new Date());
let rptCustomStart = null, rptCustomEnd = null;
let rptCalTrigger = null, rptCalViewDate = new Date(), rptCalTarget = 'anchor';
let rptShow = {cats:false, projs:false, tags:true};
let rptDrillCat = null;
let rptDrillCleared = false;

window.rptSelectDrillCat = function(cat) {
  rptDrillCat = cat;
  rptDrillCleared = false;
  renderReports();
};
window.rptClearDrill = function() {
  rptDrillCat = null;
  rptDrillCleared = true;
  renderReports();
};
function rptResetDrillOnPeriodChange() { rptDrillCleared = false; }

window.toggleRptSection = function(key) {
  rptShow[key] = !rptShow[key];
  renderReports();
};
window.rptAll = function() { rptShow={cats:true,projs:true,tags:true}; renderReports(); };
window.rptClear = function() { rptShow={cats:false,projs:false,tags:false}; renderReports(); };

function weekBounds(ds) {
  const d = new Date(ds+'T00:00:00'), day = d.getDay();
  const mon = new Date(d); mon.setDate(d.getDate()+(day===0?-6:1-day));
  const sun = new Date(mon); sun.setDate(mon.getDate()+6);
  return {mon:calFmt(mon),sun:calFmt(sun),monDate:mon,sunDate:sun};
}

function fmtDs(ds, style) {
  const d = new Date(ds+'T00:00:00');
  if (style==='long') return d.toLocaleDateString('en-NZ',{weekday:'short',day:'numeric',month:'short',year:'numeric'});
  if (style==='month') return d.toLocaleDateString('en-NZ',{month:'long',year:'numeric'});
  return d.toLocaleDateString('en-NZ',{day:'numeric',month:'short',year:'numeric'});
}

function getRptEntries() {
  const base = activeChips.size===0?E:E.filter(e=>activeChips.has(e.cat)||e.tags.some(t=>activeChips.has(t)));
  if (rptMode==='all') return base;
  if (rptMode==='day') return base.filter(e=>e.date===rptAnchor);
  if (rptMode==='week') { const {mon,sun}=weekBounds(rptAnchor); return base.filter(e=>e.date>=mon&&e.date<=sun); }
  if (rptMode==='month') return base.filter(e=>e.date.startsWith(rptAnchor.slice(0,7)));
  if (rptMode==='custom') return base.filter(e=>(!rptCustomStart||e.date>=rptCustomStart)&&(!rptCustomEnd||e.date<=rptCustomEnd));
  return base;
}

window.rptNav = function(dir) {
  const b = getEntriesDateBounds();
  const today = calFmt(new Date());
  if (rptMode==='day') rptAnchor=addCalendarDaysStr(rptAnchor,dir);
  else if (rptMode==='week') rptAnchor=addCalendarDaysStr(rptAnchor,dir*7);
  else if (rptMode==='month') rptAnchor=addMonthStr(rptAnchor,dir);
  if (b && rptAnchor < b.min) rptAnchor = b.min;
  if (rptAnchor > today) rptAnchor = today;
  rptResetDrillOnPeriodChange();
  updateRptRange(); renderReports();
};

function rptNavArrows(label, calTarget) {
  const b = getEntriesDateBounds();
  const today = calFmt(new Date());
  let prevD, nextD;
  if (rptMode==='day') { prevD=addCalendarDaysStr(rptAnchor,-1); nextD=addCalendarDaysStr(rptAnchor,1); }
  else if (rptMode==='week') { prevD=addCalendarDaysStr(rptAnchor,-7); nextD=addCalendarDaysStr(rptAnchor,7); }
  else { prevD=addMonthStr(rptAnchor,-1); nextD=addMonthStr(rptAnchor,1); }
  const pd=b&&prevD<b.min, nd=nextD>today;
  return `<button class="entries-day-arrow"${pd?' disabled':''} onclick="window.rptNav(-1)">&#9664;</button>`
       + `<div class="rpt-field" style="flex:1" onclick="openRptCal(this,'${calTarget}')"><span class="rpt-field-lbl">${label}</span><span>📅</span></div>`
       + `<button class="entries-day-arrow"${nd?' disabled':''} onclick="window.rptNav(1)">&#9654;</button>`;
}

function updateRptRange() {
  const row = document.getElementById('rpt-range'); if (!row) return;
  if (rptMode==='day') {
    row.innerHTML=rptNavArrows(fmtDs(rptAnchor,'long'),'anchor');
  } else if (rptMode==='week') {
    const {monDate,sunDate}=weekBounds(rptAnchor);
    const lbl=monDate.toLocaleDateString('en-NZ',{day:'numeric',month:'short'})+' – '+sunDate.toLocaleDateString('en-NZ',{day:'numeric',month:'short',year:'numeric'});
    row.innerHTML=rptNavArrows(lbl,'anchor');
  } else if (rptMode==='month') {
    row.innerHTML=rptNavArrows(fmtDs(rptAnchor,'month'),'month');
  } else if (rptMode==='custom') {
    row.innerHTML=`<div class="rpt-field" onclick="openRptCal(this,'custom-start')"><span class="rpt-field-lbl">${rptCustomStart?fmtDs(rptCustomStart,'short'):'Start date'}</span><span>📅</span></div><div class="rpt-field" onclick="openRptCal(this,'custom-end')"><span class="rpt-field-lbl">${rptCustomEnd?fmtDs(rptCustomEnd,'short'):'End date'}</span><span>📅</span></div>`;
  } else {
    const dates=E.map(e=>e.date).filter(Boolean).sort();
    const f=dates[0]||null, l=dates[dates.length-1]||null;
    const lbl=f?(f===l?fmtDs(f,'long'):fmtDs(f,'short')+' to '+fmtDs(l,'short')):'No entries';
    const tip='Showing all entries — select another view to filter by date.';
    row.innerHTML=`<div class="rpt-field readonly" onclick="showRptTip(this,'${tip}')"><span class="rpt-field-lbl">${lbl}</span><span style="font-size:9px;opacity:0.6;">ⓘ</span></div>`;
  }
}

window.showRptTip = function(el, msg) {
  let t=document.getElementById('rpt-tip');
  if(!t){t=document.createElement('div');t.id='rpt-tip';t.className='rpt-tip';document.body.appendChild(t);}
  const r=el.getBoundingClientRect();
  t.textContent=msg; t.style.left=r.left+'px'; t.style.top=(r.bottom+4)+'px'; t.style.display='block';
  clearTimeout(t._h); t._h=setTimeout(()=>t.style.display='none',3000);
};

window.openRptCal = function(el, target) {
  const existing=document.getElementById('rpt-cal');
  if(existing&&rptCalTrigger===el){existing.remove();rptCalTrigger=null;return;}
  if(existing)existing.remove();
  rptCalTarget=target; rptCalTrigger=el;
  const anchor=target==='custom-start'?rptCustomStart:target==='custom-end'?rptCustomEnd:rptAnchor;
  rptCalViewDate=anchor?new Date(anchor+'T00:00:00'):new Date();
  drawRptCal(el);
};

function drawRptCal(trigEl) {
  const old=document.getElementById('rpt-cal'); if(old)old.remove();
  const pop=document.createElement('div'); pop.id='rpt-cal'; pop.className='rpt-cal';
  const r=(trigEl||rptCalTrigger).getBoundingClientRect();
  pop.style.left=r.left+'px'; pop.style.top=(r.bottom+4)+'px';

  if(rptCalTarget==='month') {
    const yr=rptCalViewDate.getFullYear(), selYM=rptAnchor?rptAnchor.slice(0,7):'';
    const months=['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    const b2=getEntriesDateBounds();
    const todayFull=calFmt(new Date()), todayYM=todayFull.slice(0,7);
    pop.innerHTML=`<div class="cal-nav"><button class="cal-nav-btn" onclick="rptYrNav(-1)">&#8249;</button><span class="cal-nav-lbl">${yr}</span><button class="cal-nav-btn" onclick="rptYrNav(1)">&#8250;</button></div><div class="month-grid">${months.map((m,i)=>{const ym=yr+'-'+String(i+1).padStart(2,'0');const outOfRange=(b2&&ym<b2.min.slice(0,7))||ym>todayYM;const hasData=!outOfRange&&E.some(e=>e.date.startsWith(ym));const dis=outOfRange||!hasData;return`<div class="month-cell${ym===selYM?' msel':''}${outOfRange?' rpt-disabled':(!hasData?' rpt-dim':'')}"${dis?'':` onclick="rptPickMonth('${ym}')"`}>${m}</div>`;}).join('')}</div>`;
  } else {
    const b3=getEntriesDateBounds();
    const today=calFmt(new Date()), sel=rptCalTarget==='custom-start'?rptCustomStart:rptCalTarget==='custom-end'?rptCustomEnd:rptAnchor;
    const yr=rptCalViewDate.getFullYear(), mo=rptCalViewDate.getMonth();
    const first=new Date(yr,mo,1), last=new Date(yr,mo+1,0);
    const startDay=(first.getDay()+6)%7;
    const {mon:wMon,sun:wSun}=rptMode==='week'&&rptCalTarget==='anchor'?weekBounds(rptAnchor):{mon:null,sun:null};
    const dc=(ds,dim)=>{
      const oob=(b3&&ds<b3.min)||ds>today; // max is always today
      const noEntry=!oob&&!dim&&!hasEntriesOnDay(ds);
      let c='rpt-day'+(dim?' rpt-dim':'')+(oob?' rpt-disabled':'')+(noEntry?' rpt-dim':'');
      if(!oob&&!noEntry&&ds===today)c+=' rpt-today';
      if(!oob&&!noEntry&&(ds===sel||(wMon&&ds>=wMon&&ds<=wSun)))c+=' rpt-sel';
      if(!oob&&!noEntry&&rptMode==='custom'&&rptCustomStart&&rptCustomEnd&&ds>rptCustomStart&&ds<rptCustomEnd)c+=' rpt-range';
      return c;
    };
    const dayCell=(ds,dim)=>{const cls=dc(ds,dim);return`<div class="${cls}"${(cls.includes('rpt-disabled')||cls.includes('rpt-dim'))?'':` onclick="rptPickDate('${ds}')"`}>${ds.slice(8)}</div>`;};
    const hdrs=['Mo','Tu','We','Th','Fr','Sa','Su'];
    let h=hdrs.map(d=>`<div class="cal-hdr">${d}</div>`).join('');
    // Prev-month trailing days
    if(startDay>0){
      const pLast=new Date(yr,mo,0), pmo=mo===0?11:mo-1, pyr=mo===0?yr-1:yr;
      for(let i=startDay-1;i>=0;i--){
        const d=pLast.getDate()-i;
        const ds=pyr+'-'+String(pmo+1).padStart(2,'0')+'-'+String(d).padStart(2,'0');
        h+=dayCell(ds,true);
      }
    }
    // Current month
    for(let d=1;d<=last.getDate();d++){
      const ds=yr+'-'+String(mo+1).padStart(2,'0')+'-'+String(d).padStart(2,'0');
      h+=dayCell(ds,false);
    }
    // Next-month leading days
    const trailing=(startDay+last.getDate())%7;
    if(trailing>0){
      const nmo=mo===11?0:mo+1, nyr=mo===11?yr+1:yr;
      for(let d=1;d<=7-trailing;d++){
        const ds=nyr+'-'+String(nmo+1).padStart(2,'0')+'-'+String(d).padStart(2,'0');
        h+=dayCell(ds,true);
      }
    }
    pop.innerHTML=`<div class="cal-nav"><button class="cal-nav-btn" onclick="rptMonNav(-1)">&#8249;</button><span class="cal-nav-lbl">${first.toLocaleDateString('en-NZ',{month:'long',year:'numeric'})}</span><button class="cal-nav-btn" onclick="rptMonNav(1)">&#8250;</button></div><div class="cal-grid">${h}</div>`;
  }
  document.body.appendChild(pop);

  // Smart repositioning — keep calendar on-screen regardless of app position
  const pr = pop.getBoundingClientRect();
  if (pr.right > window.innerWidth - 4) {
    pop.style.left = Math.max(4, window.innerWidth - pr.width - 4) + 'px';
  }
  if (pr.bottom > window.innerHeight - 4) {
    pop.style.top = Math.max(4, r.top - pr.height - 4) + 'px';
  }
}

window.rptMonNav=function(d){rptCalViewDate=new Date(rptCalViewDate.getFullYear(),rptCalViewDate.getMonth()+d,1);drawRptCal();};
window.rptYrNav=function(d){rptCalViewDate=new Date(rptCalViewDate.getFullYear()+d,rptCalViewDate.getMonth(),1);drawRptCal();};
window.rptPickDate=function(ds){
  if(rptCalTarget==='custom-start')rptCustomStart=ds;
  else if(rptCalTarget==='custom-end')rptCustomEnd=ds;
  else rptAnchor=ds;
  document.getElementById('rpt-cal')?.remove();rptCalTrigger=null;
  rptResetDrillOnPeriodChange();
  updateRptRange();renderReports();
};
window.rptPickMonth=function(ym){rptAnchor=ym+'-01';document.getElementById('rpt-cal')?.remove();rptCalTrigger=null;rptResetDrillOnPeriodChange();updateRptRange();renderReports();};
window.rptModeChange=function(){rptMode=document.getElementById('rpt-mode').value;rptResetDrillOnPeriodChange();updateRptRange();renderReports();};

document.addEventListener('click',function(e){
  const cal=document.getElementById('rpt-cal');
  if(cal&&!cal.contains(e.target)&&!e.target.closest('.rpt-field')){cal.remove();rptCalTrigger=null;}
  const tip=document.getElementById('rpt-tip');
  if(tip&&!e.target.closest('.rpt-field.readonly'))tip.style.display='none';
});

const PIE_COLORS = ['#7c6af7','#f59e42','#e05a6b','#36b8a5','#5dba6e','#f0c040','#c47ec0','#5aa8f0','#e07830','#88b060'];

function rptEscAttr(s) {
  return String(s).replace(/&/g,'&amp;').replace(/"/g,'&quot;').replace(/</g,'&lt;');
}

function buildPieHtml(dataMap, total, opts) {
  opts = opts || {};
  const entries = Object.entries(dataMap).sort((a, b) => b[1] - a[1]);
  if (!entries.length || total === 0) return '';
  const size = opts.size || 76;
  const cx = size / 2, cy = size / 2, r = size * 0.395, innerR = size * 0.184;
  const activeKey = opts.activeKey || null;
  const clickable = !!opts.clickable;
  const pickAttr = opts.pickAttr || 'data-rpt-pick-cat';
  let cumAngle = -Math.PI / 2;
  let paths = '';
  entries.forEach(([k, v], i) => {
    const frac = v / total;
    const sa = cumAngle, ea = cumAngle + frac * 2 * Math.PI;
    cumAngle = ea;
    const color = PIE_COLORS[i % PIE_COLORS.length];
    const pick = clickable ? ` ${pickAttr}="${rptEscAttr(k)}"` : '';
    if (frac >= 0.9999) {
      paths += `<circle cx="${cx}" cy="${cy}" r="${r}" fill="${color}"${pick}/>`;
    } else {
      const x1 = (cx + r * Math.cos(sa)).toFixed(2), y1 = (cy + r * Math.sin(sa)).toFixed(2);
      const x2 = (cx + r * Math.cos(ea)).toFixed(2), y2 = (cy + r * Math.sin(ea)).toFixed(2);
      paths += `<path d="M${cx},${cy}L${x1},${y1}A${r},${r},0,${frac > 0.5 ? 1 : 0},1,${x2},${y2}Z" fill="${color}"${pick}/>`;
    }
  });
  const legend = entries.map(([k, v], i) => {
    const active = activeKey === k ? ' rpt-pie-active' : '';
    const pick = clickable ? ` ${pickAttr}="${rptEscAttr(k)}"` : '';
    return `<div class="rpt-pie-legend-row${active}"${pick}>
      <div class="rpt-pie-dot" style="background:${PIE_COLORS[i % PIE_COLORS.length]}"></div>
      <span class="rpt-pie-name" title="${rptEscAttr(k)}">${k}</span>
      <span class="rpt-pie-pct">${Math.round(v / total * 100)}%&ensp;${fmt(v)}</span>
    </div>`;
  }).join('');
  const clickCls = clickable ? ' rpt-pie-clickable' : '';
  return `<div class="rpt-pie-wrap${clickCls}">
    <svg viewBox="0 0 ${size} ${size}" width="${size}" height="${size}" style="flex-shrink:0;border-radius:50%;">
      ${paths}
      <circle cx="${cx}" cy="${cy}" r="${innerR}" fill="var(--surface-solid)" opacity="0.82"/>
    </svg>
    <div class="rpt-pie-legend">${legend}</div>
  </div>`;
}

function wireRptPiePickers(root, handler) {
  if (!root) return;
  root.querySelectorAll('[data-rpt-pick-cat]').forEach(node => {
    node.onclick = () => handler(node.getAttribute('data-rpt-pick-cat'));
  });
}

function renderPieChart(bC, tot, activeCat) {
  const el = document.getElementById('rpt-pie');
  if (!el) return;
  if (!Object.keys(bC).length || tot === 0) { el.innerHTML = ''; return; }
  el.innerHTML = buildPieHtml(bC, tot, { activeKey: activeCat, clickable: true });
  wireRptPiePickers(el, window.rptSelectDrillCat);
}

function subcatMapForDrill(work, cat) {
  const m = {};
  work.filter(e => e.cat === cat).forEach(e => {
    const k = e.proj || '(No sub category)';
    m[k] = (m[k] || 0) + e.dur;
  });
  return m;
}

function syncRptDrillCat(bC) {
  const sorted = Object.entries(bC).sort((a, b) => b[1] - a[1]);
  if (!sorted.length) { rptDrillCat = null; return; }
  if (rptDrillCleared) return;
  if (rptDrillCat && bC[rptDrillCat]) return;
  rptDrillCat = sorted[0][0];
}

function renderDrillSection(work, bC) {
  const chipsEl = document.getElementById('rpt-drill-chips');
  const pieEl = document.getElementById('rpt-drill-pie');
  const blockEl = document.getElementById('rpt-drill');
  if (!chipsEl || !pieEl || !blockEl) return;
  const catEntries = Object.entries(bC).sort((a, b) => b[1] - a[1]);
  if (!catEntries.length) {
    chipsEl.innerHTML = '';
    pieEl.innerHTML = '';
    blockEl.style.display = 'none';
    return;
  }
  blockEl.style.display = '';
  chipsEl.innerHTML = catEntries.map(([cat]) => {
    const esc = cat.replace(/'/g, "\\'");
    return `<button type="button" class="chip${rptDrillCat === cat ? ' active' : ''}" onclick="window.rptSelectDrillCat('${esc}')">${cat}</button>`;
  }).join('') + `<button type="button" class="chip chip-clear" onclick="window.rptClearDrill()">Clear</button>`;
  if (!rptDrillCat || rptDrillCleared) {
    pieEl.innerHTML = '<div class="rpt-drill-empty">Select a category above or click the overview pie</div>';
    return;
  }
  const bSub = subcatMapForDrill(work, rptDrillCat);
  const subTot = Object.values(bSub).reduce((a, n) => a + n, 0);
  if (!subTot) {
    pieEl.innerHTML = '<div class="rpt-drill-empty">No sub category time for this category</div>';
    return;
  }
  pieEl.innerHTML = buildPieHtml(bSub, subTot, { size: 64 });
}

function renderReports() {
  updateRptRange();
  const f=getRptEntries(), work=f.filter(e=>!isBreak(e)), brks=f.filter(e=>isBreak(e));
  const tot=work.reduce((a,e)=>a+e.dur,0), totB=brks.reduce((a,e)=>a+e.dur,0), days=new Set(work.map(e=>e.date)).size;
  document.getElementById('metrics').innerHTML=`<div class="metric"><div class="metric-val">${fmt(tot)}</div><div class="metric-lbl">Work time</div></div><div class="metric"><div class="metric-val">${fmt(totB)}</div><div class="metric-lbl">Breaks</div></div><div class="metric"><div class="metric-val">${days}</div><div class="metric-lbl">Days</div></div><div class="metric"><div class="metric-val">${days>0?fmt(Math.round(tot/days)):'0m'}</div><div class="metric-lbl">Avg/day</div></div>`;
  function bars(g,id){const mx=Math.max(...Object.values(g),1);document.getElementById(id).innerHTML=Object.entries(g).sort((a,b)=>b[1]-a[1]).map(([k,v])=>`<div class="bar-row"><div class="bar-name" title="${k}">${k}</div><div class="bar-track"><div class="bar-fill" style="width:${Math.round(v/mx*100)}%"></div></div><div class="bar-val">${fmt(v)}</div></div>`).join('')||'<div class="empty">None</div>';}
  const bC={},bP={},bT={};
  work.forEach(e=>{if(e.cat)bC[e.cat]=(bC[e.cat]||0)+e.dur;if(e.proj)bP[e.proj]=(bP[e.proj]||0)+e.dur;e.tags.forEach(t=>{bT[t]=(bT[t]||0)+e.dur;});});
  syncRptDrillCat(bC);
  renderPieChart(bC, tot, rptDrillCat);
  renderDrillSection(work, bC);
  // Section chips
  const chipData = [{key:'cats',label:'Categories'},{key:'projs',label:'Sub categories'},{key:'tags',label:'Tags'}];
  const allRptOn = rptShow.cats && rptShow.projs && rptShow.tags;
  document.getElementById('rpt-chips').innerHTML =
    `<button class="chip${allRptOn?' active':''}" onclick="window.rptAll()">All</button>`+
    chipData.map(({key,label})=>`<button class="chip${rptShow[key]?' active':''}" onclick="window.toggleRptSection('${key}')">${label}</button>`).join('')+
    `<button class="chip chip-clear" onclick="window.rptClear()">Clear</button>`;
  // Show/hide sections and render bars
  document.getElementById('rpt-sec-cats').style.display = rptShow.cats ? '' : 'none';
  document.getElementById('rpt-sec-projs').style.display = rptShow.projs ? '' : 'none';
  document.getElementById('rpt-sec-tags').style.display = rptShow.tags ? '' : 'none';
  if (rptShow.cats) bars(bC,'cat-bars');
  if (rptShow.projs) bars(bP,'proj-bars');
  if (rptShow.tags) bars(bT,'tag-bars');
}

function addMonthStr(ds, n) {
  const d = new Date(ds + 'T00:00:00');
  d.setMonth(d.getMonth() + n);
  return calFmt(d);
}

window.setEntriesMode = function(mode) {
  entriesFilterMode = mode;
  render();
};

function getEntriesFiltered(base) {
  if (entriesFilterMode === 'day') return base.filter(e => e.date === entriesFilterDate);
  if (entriesFilterMode === 'week') { const {mon,sun}=weekBounds(entriesFilterDate); return base.filter(e=>e.date>=mon&&e.date<=sun); }
  if (entriesFilterMode === 'month') return base.filter(e=>e.date.startsWith(entriesFilterDate.slice(0,7)));
  if (entriesFilterMode === 'custom') return base.filter(e=>(!entriesCustomStart||e.date>=entriesCustomStart)&&(!entriesCustomEnd||e.date<=entriesCustomEnd));
  return base; // all
}

function entryCard(e) {
  const hasNotes = e.notes && e.notes.trim();
  const notesToggle = hasNotes ? `<button class="entry-notes-toggle" id="ent-${e.id}" onclick="window.toggleEntryNotes(${e.id})" title="Show / hide details">▾</button>` : '';
  const notesRow = hasNotes ? `<div class="entry-notes" id="en-${e.id}">${e.notes.replace(/</g,'&lt;')}</div>` : '';
  return `<div class="entry ${isBreak(e)?'is-break':''}"><div class="entry-top"><span class="entry-desc">${isBreak(e)?'<span class="break-badge">break</span>':e.cat?`<span class="cat-badge">${e.cat}</span>`:''}${e.desc}${e.tags.map(t=>`<span class="tag">${t}</span>`).join('')}</span><span class="entry-dur">${fmt(e.dur)}</span>${notesToggle}<button class="edit-btn" onclick="window.editEntry(${e.id})" title="Edit">✎</button><button class="del" onclick="window.del(${e.id})">&#10005;</button></div><div class="entry-meta">${e.date} &middot; ${e.start}&ndash;${e.end}${e.proj?' &middot; '+e.proj:''}</div>${notesRow}</div>`;
}

window.toggleEntryNotes = function(id) {
  const notes = document.getElementById('en-'+id);
  const btn = document.getElementById('ent-'+id);
  if (!notes) return;
  const opening = !notes.classList.contains('open');
  notes.classList.toggle('open', opening);
  if (btn) btn.classList.toggle('open', opening);
};

function render() {
  if (gridEditMode) return;
  rdds(); rmng();
  // Date-filtered entries (before chip filter) — chips only show what's in current period
  const fDate = getEntriesFiltered(E);
  const ac=[...new Set(fDate.map(e=>e.cat).filter(Boolean))],at=[...new Set(fDate.flatMap(e=>e.tags))];
  const allItems=[...ac,...at];
  // "All" active = nothing selected, or every visible item's cat/tag is in the set
  const allOn=allItems.length>0&&allItems.every(v=>activeChips.has(v));
  // Apply chip filter on top of date filter
  let f = (activeChips.size===0||allOn) ? fDate : fDate.filter(e=>activeChips.has(e.cat)||e.tags.some(t=>activeChips.has(t)));
  const chipsEl = document.getElementById('chips');
  if (allItems.length === 0) {
    chipsEl.innerHTML = '';
  } else {
    chipsEl.innerHTML=
      `<button class="chip${allOn?' active':''}" onclick="window.chipsAll()">All</button>`+
      ac.map(c=>`<button class="chip${activeChips.has(c)?' active':''}" onclick="window.toggleChip('${c.replace(/'/g,"\\'")}')">${c}</button>`).join('')+
      at.map(t=>`<button class="chip${activeChips.has(t)?' active':''}" onclick="window.toggleChip('${t.replace(/'/g,"\\'")}')">${t}</button>`).join('')+
      `<button class="chip chip-clear" onclick="window.chipsClear()">Clear</button>`;
  }
  const elList = document.getElementById('entries-list');
  if (!f.length) {
    const today = calFmt(new Date());
    const chipFiltered = activeChips.size > 0 && fDate.length > 0;
    const wrongDay = entriesFilterMode === 'day' && entriesFilterDate !== today;
    let msg = E.length ? 'No entries in this range' : 'No entries yet';
    if (chipFiltered) msg = 'No entries match the selected filters — tap Clear on the chips above';
    else if (wrongDay && E.some(e => e.date === today)) msg = 'Nothing logged for this day — double-click the date bar for Today';
    elList.innerHTML = `<div class="empty">${msg}</div>`;
  } else {
    // Helper: render a sorted-newest-first day's entries with gap indicators
    function renderDayEntries(es) {
      const day = sortNewestFirst(es); // newest start time at top
      let html = '';
      for (let i = 0; i < day.length; i++) {
        html += entryCard(day[i]);
        if (i < day.length - 1) html += gapIndicator(day[i].date, day[i+1].end, day[i].start);
      }
      return html;
    }
    if (entriesFilterMode === 'day') {
      elList.innerHTML = renderDayEntries(f);
    } else {
      const groups = {};
      f.forEach(e => { if (!groups[e.date]) groups[e.date] = []; groups[e.date].push(e); });
      elList.innerHTML = Object.keys(groups).sort((a,b)=>b.localeCompare(a)).map(date =>
        `<div class="entry-date-hdr">${fmtDs(date,'long')}</div>${renderDayEntries(groups[date])}`
      ).join('');
    }
  }
  syncEntriesDayBar();
  renderReports();
}

// GRID EDIT
let gridEditMode = false;
let gridDraft = null; // { dateStr: [entries] }
let gridDraftPSnapshot = null; // snapshot of P at grid entry, for discard

function gridHasChanges() {
  if (!gridDraft) return false;
  return Object.values(gridDraft).some(dayEntries =>
    dayEntries.some(d => {
      const orig = E.find(e => e.id === d.id);
      if (!orig) return d._isGap ? !!d.desc : !!(d.desc || d.start); // gap rows only count if desc filled
      return d.desc !== orig.desc || d.cat !== orig.cat || d.proj !== orig.proj || d.start !== orig.start || d.end !== orig.end;
    })
  );
}

function confirmLeaveGrid(onProceed) {
  if (!gridEditMode) { onProceed(); return; }
  if (!gridHasChanges()) { exitGridEdit(false); onProceed(); return; }
  showModal(
    'Discard unsaved changes?',
    'You have unsaved edits in the grid. Leaving will discard them.',
    { fn: () => { exitGridEdit(true); onProceed(); } },
    { confirm: 'Discard changes', cancel: 'Keep editing' }
  );
}

function exitGridEdit(restoreProjects) {
  if (restoreProjects && gridDraftPSnapshot) P = gridDraftPSnapshot;
  gridEditMode = false;
  gridDraft = null;
  gridDraftPSnapshot = null;
  const btn = document.getElementById('grid-edit-btn');
  if (btn) btn.style.display = '';
  render();
}

function gridDayEntries() { return gridDraft[entriesFilterDate] || []; }

function gridSwitchDay() {
  if (!gridDraft[entriesFilterDate]) {
    gridDraft[entriesFilterDate] = injectGridGapRows(JSON.parse(JSON.stringify(E.filter(e => e.date === entriesFilterDate))), entriesFilterDate);
  }
  syncEntriesDayBar();
  renderGrid();
}

window.enterGridEdit = function() {
  const dayEntries = E.filter(e => e.date === entriesFilterDate);
  gridEditMode = true;
  gridDraftPSnapshot = JSON.parse(JSON.stringify(P));
  gridDraft = {};
  gridDraft[entriesFilterDate] = injectGridGapRows(JSON.parse(JSON.stringify(dayEntries)), entriesFilterDate);
  ipcRenderer.send('resize-app', 'max');
  const btn = document.getElementById('grid-edit-btn');
  if (btn) btn.style.display = 'none';
  renderGrid();
};

window.saveGridEdit = function() {
  Object.values(gridDraft).forEach(dayEntries => {
    dayEntries.forEach(d => {
      const sm = mins(d.start), em = mins(d.end);
      if (sm >= 0 && em > sm) d.dur = em - sm;
      const idx = E.findIndex(e => e.id === d.id);
      if (idx !== -1) { const saved = {...E[idx], ...d}; delete saved._isGap; E[idx] = saved; }
      else if (d._isGap) { if (d.desc) { const s={...d}; delete s._isGap; E.unshift(s); } } // gap row: only save if desc filled
      else if (d.desc || d.start) E.unshift(d); // normal new row
      if (d.proj && d.cat) {
        const p = P.find(p => p.name === d.proj && !p.cat);
        if (p) p.cat = d.cat;
      }
    });
  });
  sv();
  exitGridEdit();
};

window.discardGridEdit = function() { exitGridEdit(true); };

function allProjOpts(selected) {
  return '<option value="">—</option>'
    + '<option value="__new__">＋ New sub category…</option>'
    + P.map(p => `<option value="${p.name.replace(/"/g,'&quot;')}"${p.name===selected?' selected':''}>${p.name}</option>`).join('');
}

function renderGrid() {
  const el = document.getElementById('entries-list');
  if (!gridDraft) return;
  const day = gridDayEntries();
  // sort newest-first in-place so data-i indices match the sorted order
  day.sort((a,b) => { if(!a.start&&!b.start)return 0; if(!a.start)return 1; if(!b.start)return -1; return b.start.localeCompare(a.start); });
  const rows = day.map((e, i) => {
    const isGap = !!e._isGap;
    const catOpts = '<option value="">—</option>' + C.map(c => `<option value="${c.replace(/"/g,'&quot;')}"${c===e.cat?' selected':''}>${c}</option>`).join('');
    const notesRow = (!isGap && e.notes) ? `<tr class="grid-notes-row"><td colspan="6"><textarea class="gd-notes" data-i="${i}" rows="1">${(e.notes||'').replace(/</g,'&lt;')}</textarea></td></tr>` : '';
    return `<tr${isGap?' class="grid-gap-row" title="Gap in your day — fill in to log this time"':''}>
      <td><input class="gd-f" data-i="${i}" data-f="desc" value="${e.desc.replace(/"/g,'&quot;').replace(/</g,'&lt;')}" placeholder="${isGap?'Gap — fill in to log':''}"></td>
      <td><select class="gd-proj" data-i="${i}">${allProjOpts(e.proj)}</select></td>
      <td><select class="gd-cat" data-i="${i}">${catOpts}</select></td>
      <td><input class="gd-f gd-t" data-i="${i}" data-f="start" value="${e.start}" maxlength="5"></td>
      <td><input class="gd-f gd-t" data-i="${i}" data-f="end" value="${e.end}" maxlength="5"></td>
      <td class="grid-dur" data-i="${i}">${isGap ? `<button class="gap-grid-del" onclick="window.gridDeleteGapRow(${i})" title="Dismiss gap">✕</button>` : (e.dur ? fmt(e.dur) : '')}</td>
    </tr>${notesRow}`;
  }).join('');
  el.innerHTML = `<table class="grid-table">
    <thead><tr><th>Description</th><th>Sub category</th><th>Category</th><th>Start</th><th>End</th><th></th></tr></thead>
    <tbody>${rows || '<tr><td colspan="6" class="empty" style="text-align:center;padding:12px;">No entries — use + Add entry below</td></tr>'}</tbody>
  </table>
  <div class="grid-actions">
    <button class="btn-add-row" onclick="window.gridAddRow()" style="flex:1;padding:5px;font-size:10px;background:var(--surface);color:var(--accent);border:1px dashed var(--accent);border-radius:4px;cursor:pointer;">+ Add entry</button>
    <button class="btn-save" onclick="window.saveGridEdit()">Save changes</button>
    <button class="btn-discard" onclick="window.discardGridEdit()">Discard changes</button>
  </div>`;
  el.querySelectorAll('.gd-f').forEach(inp => {
    inp.addEventListener('input', () => {
      const i = +inp.dataset.i, f = inp.dataset.f;
      gridDayEntries()[i][f] = inp.value;
      if (f === 'start' || f === 'end') {
        window.fmtT(inp);
        const d = gridDayEntries()[i];
        const sm = mins(d.start), em = mins(d.end);
        if (sm >= 0 && em > sm) { d.dur = em - sm; el.querySelector(`.grid-dur[data-i="${i}"]`).textContent = fmt(em - sm); }
      }
    });
  });
  el.querySelectorAll('.gd-cat').forEach(sel => {
    sel.addEventListener('change', () => { gridDayEntries()[+sel.dataset.i].cat = sel.value; });
  });
  el.querySelectorAll('.gd-notes').forEach(ta => {
    ta.style.height = 'auto';
    ta.style.height = ta.scrollHeight + 'px';
    ta.addEventListener('input', () => {
      const i = +ta.dataset.i;
      gridDayEntries()[i].notes = ta.value;
      ta.style.height = 'auto';
      ta.style.height = ta.scrollHeight + 'px';
    });
  });
  el.querySelectorAll('.gd-proj').forEach(sel => {
    sel.addEventListener('change', () => {
      const i = +sel.dataset.i;
      if (sel.value === '__new__') {
        const name = prompt('New sub category name:');
        if (!name || !name.trim()) { sel.value = gridDayEntries()[i].proj || ''; return; }
        const trimmed = name.trim();
        const catName = prompt('Category for "' + trimmed + '" (required):\n(' + (C.length ? C.join(', ') : 'no categories yet — type a new one') + ')');
        if (!catName || !catName.trim()) { sel.value = gridDayEntries()[i].proj || ''; return; }
        const cat = C.find(c => c.toLowerCase() === catName.trim().toLowerCase()) || catName.trim();
        if (!P.find(p => p.name.toLowerCase() === trimmed.toLowerCase())) { P.push({name:trimmed, cat}); if(!C.includes(cat)) C.push(cat); sv(); }
        gridDayEntries()[i].proj = trimmed;
        if (cat && !gridDayEntries()[i].cat) gridDayEntries()[i].cat = cat;
        renderGrid();
        return;
      }
      gridDayEntries()[i].proj = sel.value;
    });
  });
}

window.gridAddRow = function() {
  if (!gridDraft[entriesFilterDate]) gridDraft[entriesFilterDate] = [];
  gridDraft[entriesFilterDate].push({id: Date.now()+Math.random(), desc: '', cat: '', proj: '', date: entriesFilterDate, start: '', end: '', dur: 0, tags: []});
  renderGrid();
  const rows = document.querySelectorAll('#entries-list .grid-table tbody tr');
  if (rows.length) rows[rows.length-1].querySelector('input').focus();
};

window.gridDeleteGapRow = function(i) {
  const day = gridDayEntries();
  const gap = day[i];
  if (!gap || !gap._isGap) return;
  // Persist the dismissal so it doesn't reappear in list view either
  dismissedGaps.add(gapKey(gap.date, gap.start, gap.end));
  saveDismissedGaps();
  day.splice(i, 1);
  renderGrid();
};

// INIT
const savedTheme = dbGet('tt_theme') || 'space';
window.setTheme(savedTheme);
window.calPickToday();
resetEntriesFilterToToday();
(function wireEntriesDayBar() {
  const picker = document.getElementById('entries-day-picker');
  const prev = document.getElementById('entries-day-prev');
  const next = document.getElementById('entries-day-next');
  const displayBtn = document.getElementById('entries-day-display');
  if (!picker || !prev || !next) return;
  // Display button opens the native date picker explicitly (more reliable in Electron)
  if (displayBtn) {
    displayBtn.addEventListener('click', function() {
      if (picker.disabled) return;
      try { picker.showPicker(); } catch(e) { picker.focus(); picker.click(); }
    });
  }
  picker.addEventListener('change', function() {
    if (this.disabled || !this.value) return;
    entriesFilterDate = this.value;
    if (gridEditMode) { gridSwitchDay(); return; }
    render();
  });
  prev.addEventListener('click', function() {
    if (this.disabled) return;
    if (entriesFilterMode === 'week') entriesFilterDate = addCalendarDaysStr(entriesFilterDate, -7);
    else if (entriesFilterMode === 'month') entriesFilterDate = addMonthStr(entriesFilterDate, -1);
    else entriesFilterDate = addCalendarDaysStr(entriesFilterDate, -1);
    if (gridEditMode) { gridSwitchDay(); return; }
    render();
  });
  next.addEventListener('click', function() {
    if (this.disabled) return;
    if (entriesFilterMode === 'week') entriesFilterDate = addCalendarDaysStr(entriesFilterDate, 7);
    else if (entriesFilterMode === 'month') entriesFilterDate = addMonthStr(entriesFilterDate, 1);
    else entriesFilterDate = addCalendarDaysStr(entriesFilterDate, 1);
    if (gridEditMode) { gridSwitchDay(); return; }
    render();
  });
  const ecrStart = document.getElementById('ecr-start');
  const ecrEnd = document.getElementById('ecr-end');
  if (ecrStart) ecrStart.addEventListener('change', function() { entriesCustomStart = this.value; render(); });
  if (ecrEnd) ecrEnd.addEventListener('change', function() { entriesCustomEnd = this.value; render(); });
})();
initQuote();
startClock();
render();
doBackup(); // backup on startup, after data is loaded
window.addEventListener('beforeunload', doBackup);
(function wireStartField() {
  const s = document.getElementById('start');
  if (!s) return;
  s.addEventListener('input', syncEndField);
  s.addEventListener('keyup', syncEndField);
  s.addEventListener('paste', function() { setTimeout(syncEndField, 0); });
  s.addEventListener('blur', commitStart);
  s.addEventListener('keydown', function(ev) {
    if (ev.key === 'Enter') { ev.preventDefault(); commitStart(); document.getElementById('end').focus(); }
  });
  document.getElementById('end').addEventListener('click', function() {
    if (this.disabled) showToast('END field disabled: no START time chosen');
  });
  syncEndField();
})();
window.addEventListener('beforeunload', e => { if (gridEditMode) { e.preventDefault(); e.returnValue = ''; } });

// Backdrop click closes modal
document.getElementById('tt-modal').addEventListener('click', function(e) {
  if (e.target === this) window.closeModal();
});

// Click outside rename row closes it
document.addEventListener('click', function(e) {
  if (ren.type && !e.target.closest('#cat-list') && !e.target.closest('#project-list') && !e.target.closest('#tag-list')) {
    window.cr();
  }
});
